<template>
  <div>
    <div class="ms-ps-title">
      {{ $t('configurations.connectMicrosoftAccountPage.title') }}
    </div>
    <div class="ms-ps-subtitle">
      {{ $t('configurations.connectMicrosoftAccountPage.subtitle') }}
    </div>
    <div style="margin-top: 44px;">
      <f-button variant="primary" style="margin-right: 12px"
      :loading="loading" @click="onClickSignIn">
        {{ $t('general.buttons.signIn') }}
      </f-button>
      <f-button v-if="isNewAccount" variant="outline-secondary" @click="onClickCreateNew">
        {{ $t('general.buttons.createNew') }}
      </f-button>
    </div>
  </div>
</template>

<script>

import { mapState } from 'vuex';
import { signInMSAccount, getAccountStatus } from '../../services/bingads.service';
import AccountStatus from '../../models/enums/account-status';
import i18n from '../../lib/i18n';

export default {
  data() {
    let url = window.location.href;
    url = url.replace('&#', '#');
    const redirectUrl = escape(url);
    return {
      redirectUrl,
      loading: false,
      isNewAccount: false,
    };
  },
  computed: {
    ...mapState({
      tokenPsAccounts: (state) => state.accounts.tokenPsAccounts,
    }),
  },
  mounted() {
    this.getAccountStatus();
    const queryString = window.location.search;
    const lowerCaseQueryString = queryString.toLowerCase();
    const urlParams = new URLSearchParams(lowerCaseQueryString);
    const message = urlParams.get('message');
    const errorMap = i18n.t('general.errorMap');
    const errorMessage = message === 'prestashopsetupuettagwriteerror' ? errorMap.PrestaShopSetupUetTagWriteError : errorMap.others;
    const h = this.$createElement;
    const vNodesMsg = h(
      'p',
      {
        class: ['text-center', 'mb-0'],
      },
      [
        errorMessage,
        h(
          'a',
          {
            class: 'fluent-toast-link',
            attrs: {
              href: 'https://help.ads.microsoft.com/#apex/ads/en/60171/1/#related_articles',
              target: '_blank',
            },
          },
          i18n.t('general.actions.learnMore'),
        ),
      ],
    );
    if (message === 'connectfailed' || message === 'prestashopsetupuettagwriteerror') {
      this.$bvToast.toast([vNodesMsg], {
        toaster: 'b-toaster-bottom-center',
        noCloseButton: true,
        title: i18n.t('general.actions.learnMore'),
        toastClass: 'fluent-toast',
        solid: true,
        static: true,
        variant: 'danger',
        offset: 200,
      });
    }
  },
  methods: {
    async onClickSignIn() {
      this.loading = true;
      try {
        const redirectUrl = await signInMSAccount(this.redirectUrl, this.storeUrl, this.storeId);
        window.top.location.href = redirectUrl;
      } catch {
        this.loading = false;
      }
    },
    onClickCreateNew() {
      this.$router.push({ name: 'create-microsoft-account' });
    },
    async getAccountStatus() {
      // eslint-disable-next-line camelcase
      const { bingads_account_status } = await getAccountStatus();
      // eslint-disable-next-line camelcase
      this.isNewAccount = bingads_account_status !== AccountStatus.DISCONNECTED
        // eslint-disable-next-line camelcase
        && bingads_account_status !== AccountStatus.SIGNED_UP_NOT_CONNECTED
        // eslint-disable-next-line camelcase
        && bingads_account_status !== AccountStatus.SIGN_UP_INVITATION_SENT_NOT_ACCEPTED;
    },
  },
};

</script>

<style lang="scss" scoped></style>
