<template>
  <b-overlay :show="!display">
    <div v-if="!display" class="empty-content" />
    <div v-else>
      <CampaignDashboard v-if="isDashboardShow" @editCampaign="changePage" />
      <CreateCampaign v-else @editCampaign="changePage" />
    </div>
  </b-overlay>
</template>

<script>
import { mapActions, mapState } from 'vuex';
import CampaignDashboard from '../../components/campaign/CampaignDashboard.vue';
import CreateCampaign from '../../components/campaign/CreateCampaign.vue';
import { CampaignPaused } from '../../models/enums/campaign-status';

export default {
  components: {
    CampaignDashboard,
    CreateCampaign,
  },
  data() {
    return {
      isDashboardShow: false,
      display: false,
      progress: 0,
    };
  },
  computed: {
    ...mapState({
      campaignId: (state) => state.market.campaignId,
      campaignName: (state) => state.market.campaignName,
      campaignStatus: (state) => state.market.campaignStatus,
      dailyBudget: (state) => state.market.dailyBudget,
      salesCountryCode: (state) => state.market.salesCountryCode,
    }),
  },
  mounted() {
    this.init();
    this.startTimer();
  },
  methods: {
    ...mapActions('market', ['getCampaignInfo']),
    async init() {
      await this.getCampaignInfo();
      this.isDashboardShow = (this.campaignId !== 0
        && this.campaignStatus !== CampaignPaused);
      this.display = true;
    },
    changePage(flag) {
      this.isDashboardShow = flag;
    },
    startTimer() {
      setInterval(() => {
        switch (true) {
          case (this.progress < 50):
            this.progress += 5;
            break;
          case (this.progress < 80):
            this.progress += 3;
            break;
          case (this.progress < 90):
            this.progress += 1;
            break;
          case (this.progress < 99):
            this.progress += 0.5;
            break;
          default:
            break;
        }
      }, 10);
    },
  },
};
</script>

<style scoped lang="scss">
.empty-content {
  height: 240px;
}
</style>
