import i18n from '../lib/i18n';
import ErrorCode from '../models/enums/error-code';

const errorMap = i18n.t('general.errorMap');
errorMap.UnallowedStoreDestinationUrl = i18n.t('general.errorMap.UnallowedStoreDestinationUrl', [window.shopUrlForMicrosoft]);
const addErrorHandler = (instance) => {
  instance.interceptors.response.use((response) => response, (error) => {
    let errorMessage = errorMap.others;
    if (error.response.data?.error !== null) {
      errorMessage = error.response.data?.error?.picApiPoolErrorCode
        ? errorMap[error.response.data.error.picApiPoolErrorCode] : errorMap.others;
    }
    if (error.response.data?.error?.picApiPoolErrorCode === ErrorCode[0]
      || error.response.data?.error?.picApiPoolErrorCode === ErrorCode[1]) {
      return Promise.reject(error);
    }
    if (errorMessage === undefined) errorMessage = errorMap.others;
    window.$vue.$bvToast.toast(errorMessage, {
      toaster: 'b-toaster-bottom-center',
      noCloseButton: true,
      title: i18n.t('general.errorTitle.error'),
      toastClass: 'fluent-toast',
      solid: true,
      static: true,
      variant: 'danger',
    });
    return Promise.reject(error);
  });
};

export default addErrorHandler;
