import { getAccountStatus } from '../../../services/bingads.service';

const actions = {
  async getAccountStatus({
    commit,
  }) {
    const response = await getAccountStatus();
    // TODO: add logic to handle error
    const accountStatus = response.bingads_account_status;
    commit('SAVE_ACCOUNT_STATUS', accountStatus);
  },
};

export default actions;
