export default {
  SAVE_CAMPAIGN_INFO(state, campaignInfo) {
    state.campaignId = campaignInfo.campaign_id;
    state.campaignName = campaignInfo.campaign_name;
    state.campaignStatus = campaignInfo.campaign_status;
    state.dailyBudget = campaignInfo.daily_budget;
    state.salesCountryCode = campaignInfo.sales_country_code;
    state.startDate = campaignInfo.start_date;
    state.endDate = campaignInfo.end_date;
  },
  SAVE_COUPON_DURATION(state, couponDuration) {
    state.couponDuration = couponDuration;
  },
  SAVE_COUPON_CLASS(state, couponClass) {
    state.couponValue = couponClass.coupon_value;
    state.upFrontSpending = couponClass.upfront_spending;
    state.daysToSpend = couponClass.days_to_spend;
  },
};
