<!-- eslint-disable -->
<template>
  <div>
    <div v-if="isFetchConnect">
      <f-alert v-if="!isConnect" show variant="danger" style="margin-top: 16px;">
        <div v-if="!isConfirmed">
          <span>{{ $t('campaignPage.banner.confirmEmail.content', [email]) }} </span>
          <a @click="resendEmail" @keydown="() => { }">
            {{ $t('campaignPage.banner.confirmEmail.action') }}
          </a>
        </div>
        <div v-else>
          <span>{{ $t('campaignPage.banner.connectAccount') }} </span>
        </div>
      </f-alert>
      <CouponNotRedeemedBannerVue v-else />
    </div>
    <div>
      <div v-if="campaignId === 0" class="ms-ps-title">
        {{ $t('campaignPage.createCampaign.createTitle') }}
      </div>
      <div v-else class="ms-ps-title">
        {{ $t('campaignPage.createCampaign.editTitle') }}
      </div>
      <div class="ms-ps-subtitle">
        {{ $t('campaignPage.createCampaign.subtitle') }}
      </div>

      <div id="create-campaign-body">
        <div id="create-campaign-form">
          <b-form>
            <b-form-group id="input-group-1" :label="$t('campaignPage.createCampaign.campaignName.title')"
              label-for="input-1" :invalid-feedback="nameFeedback" :state="nameState">
              <b-form-input id="input-1" v-model="form.campaignName" class="campaign-form-control"
                :disabled="campaignName !== null"
                :placeholder="$t('campaignPage.createCampaign.campaignName.placeholder')" :state="nameState" />
            </b-form-group>
            <b-form-group id="input-group-2" :label="$t('campaignPage.createCampaign.campaignStatus.title')"
              label-for="input-2">
              <b-form-select id="input-2" v-model="form.campaignStatus" class="campaign-form-control"
                :options="campaignStatusOptions" />
            </b-form-group>
            <b-form-group id="input-group-3" :label="$t('campaignPage.createCampaign.campaignBudget.title')"
              label-for="input-3" :invalid-feedback="budgetFeedback" :state="budgetState">
              <div class="campaign-budget-input">
                <b-form-input id="input-3" v-model="form.campaignBudget" type="number" class="campaign-form-control"
                  :placeholder="$t('campaignPage.createCampaign.campaignBudget.placeholder')" :state="budgetState" />
                <span>{{ $t('campaignPage.createCampaign.campaignBudget.unit', [currency]) }}</span>
              </div>
              <a target="_blank" href="https://help.ads.microsoft.com/apex/index/3/en-us/51006">
                {{ $t('campaignPage.createCampaign.campaignBudget.recommended') }}
              </a>
            </b-form-group>

            <b-form-group id="input-group-4" :label="$t('campaignPage.createCampaign.targetMarket.title')"
              label-for="input-4">
              <div id="input-4" class="campaign-form-control">
                {{ form.targetMarket }}
                {{ $t('campaignPage.createCampaign.targetMarket.description') }}
              </div>
            </b-form-group>

            <b-form-group id="input-group-5" :label="$t('campaignPage.createCampaign.startDate.title')"
              label-for="input-5">
              <b-form-datepicker id="input-5" v-model="form.startDate" :min="curDate"
                :date-format-options="{ year: 'numeric', month: 'numeric', day: 'numeric' }" :disabled="startDate !== null"
                hide-header class="campaign-form-control" :locale=locale label-help="" />
            </b-form-group>

            <b-form-group id="input-group-6" :label="$t('campaignPage.createCampaign.endDate.title')" label-for="input-6">
              <b-form-radio v-model="form.isNoEndDate" name="endate" :value="true" @change="onDisableEndDate">
                {{ $t('campaignPage.createCampaign.endDate.radioGroup.noEndDate') }}
              </b-form-radio>
              <div class="campaign-end-date-radio" style="margin-top: 16px;">
                <b-form-radio v-model="form.isNoEndDate" name="endate" :value="false" @change="onEnableEndDate">
                  <div style="width: 64px; margin-right: 16px">
                    {{ $t('campaignPage.createCampaign.endDate.radioGroup.endBy') }}
                  </div>
                </b-form-radio>
                <b-form-datepicker id="input-6" v-model="form.endDate" class="campaign-input-end-date"
                  :date-format-options="{ year: 'numeric', month: 'numeric', day: 'numeric' }" hide-header
                  :disabled="!isEndDateEditable" :min="form.startDate" :locale=locale label-help="" />
              </div>
            </b-form-group>

            <b-form-group id="input-group-7" :label="$t('campaignPage.createCampaign.paymentMethod.title')"
              label-for="input-7">
              <div>
                <div>{{ $t('campaignPage.createCampaign.paymentMethod.description') }}</div>
                <div v-if="isFetchPayment" style="margin-top: 16px; margin-bottom: 16px; width:456px">
                  <f-alert :show="!paymentExist" variant="danger">
                    <div>
                      {{ $t('campaignPage.createCampaign.paymentMethod.notExist') }}
                    </div>
                  </f-alert>
                  <div v-if="paymentExist">
                    <span>
                      <img src="@/assets/image/green-tick.svg">
                      {{ $t('campaignPage.createCampaign.paymentMethod.exist') }}
                    </span>
                  </div>
                  <div style="margin-top: 8px;">
                    <a v-if="paymentExist" target="_blank" :href="paymentUrl">
                      {{ $t('campaignPage.createCampaign.paymentMethod.linkManage') }}
                    </a>
                    <a v-else target="_blank" :href="paymentUrl">
                      {{ $t('campaignPage.createCampaign.paymentMethod.linkAdd') }}
                    </a>
                  </div>
                </div>
              </div>
            </b-form-group>
          </b-form>
          <div style="margin-top: 44px;">
            <f-button type="save" variant="primary" style="margin-right: 12px" :loading="saveLoading"
              :disabled="!isSaveAvailable" @click="onClickSave">
              {{ $t('general.buttons.save') }}
            </f-button>
            <f-button type="cancel" variant="outline-secondary" @click="onClickCancel">
              {{ $t('general.buttons.cancel') }}
            </f-button>
          </div>
        </div>
        <div id="create-campaign-preview">
          <div>
            <div style="font-weight: 600; margin-bottom: 32px">
              {{ $t('campaignPage.createCampaign.preview.title') }}
            </div>
            <div id="campaign-preview-tab-bar">
              <div :class="{ active: currentPreview === 'desktop' }" @click="onClickNaviItem('desktop')"
                @keydown="() => { }">
                {{ $t('campaignPage.createCampaign.preview.desktop') }}
              </div>
              <div :class="{ active: currentPreview === 'mobile' }" @click="onClickNaviItem('mobile')" @keydown="() => { }">
                {{ $t('campaignPage.createCampaign.preview.mobile') }}
              </div>
            </div>

            <div class="description">
              {{ $t('campaignPage.createCampaign.preview.description') }}
            </div>

            <div v-if="products.length >= 3" class="image-container">
              <div v-for="(product, index) in products" :key="index">
                <img :src="product.image_url">
                <div class="limit-line">
                  {{ product.name }}
                </div>
                <div style="color: #444444">
                  {{ currencySign + '' + product.price }}
                </div>
                <div class="limit-line-storename">
                  {{ storeName }}
                </div>
              </div>
            </div>
            <div v-else>
              <img class="product-view-image" src="@/assets/image/products-preview.png">
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { mapActions, mapState } from 'vuex';
import {
  getAccountStatus, resendEmail, getPaymentInfo, upsertCampaign, checkStoreExisting,
} from '../../services/bingads.service';
import accountStatus from '../../models/enums/account-status';
import { CampaignPaused } from '../../models/enums/campaign-status';
import config from '../../config';
import CouponNotRedeemedBannerVue from './CouponNotRedeemedBanner.vue';
import MmcStoreStatus from '../../models/enums/mmc-store-status';

export default {
  components: {
    CouponNotRedeemedBannerVue,
  },
  data() {
    const campaignStatusOptions = [
      {
        value: true,
        text: this.$t('campaignPage.createCampaign.campaignStatus.enabled'),
      },
      {
        value: false,
        text: this.$t('campaignPage.createCampaign.campaignStatus.disabled'),
      },
    ];
    return {
      email: '',
      curDate: new Date(),
      currency: '',
      form: {
        campaignName: null,
        campaignStatus: true,
        campaignBudget: null,
        startDate: new Date(),
        endDate: null,
        isNoEndDate: true,
        targetMarket: window.defaultCountry,
      },
      isEndDateEditable: false,
      // TODO: need to use enum
      currentPreview: 'desktop',
      products: window.product,
      storeName: window.contextPsAccounts.currentShop.name,
      currencySign: window.currencySign,
      isConnect: true,
      isConfirmed: true,
      isCouponAvailable: false,
      campaignStatusOptions,
      isFetchPayment: false,
      paymentExist: false,
      accountId: null,
      customerId: null,
      saveLoading: false,
      isFetchConnect: false,
      locale: window.i18nSettings.languageLocale,
    };
  },

  computed: {
    ...mapState({
      campaignId: (state) => state.market.campaignId,
      campaignName: (state) => state.market.campaignName,
      campaignStatus: (state) => state.market.campaignStatus,
      dailyBudget: (state) => state.market.dailyBudget,
      salesCountryCode: (state) => state.market.salesCountryCode,
      couponValue: (state) => state.market.couponValue,
      upFrontSpending: (state) => state.market.upFrontSpending,
      couponDuration: (state) => state.market.couponDuration,
      startDate: (state) => state.market.startDate,
      endDate: (state) => state.market.endDate,
    }),
    paymentUrl() {
      return `${config.bingadsPaymentUrl}aid=${this.accountId}&cid=${this.customerId}`;
    },
    isSaveAvailable() {
      return this.form.campaignName !== '' && this.form.campaignName !== null && this.form.campaignBudget !== '' && this.form.campaignBudget !== null
        && parseFloat(this.form.campaignBudget) > 0
        && (this.form.endDate !== null || this.form.isNoEndDate) && this.paymentExist;
    },
    nameFeedback() {
      return this.$t('campaignPage.createCampaign.campaignName.nameRequired');
    },
    nameState() {
      return this.form.campaignName === null || this.form.campaignName?.length > 0;
    },
    budgetFeedback() {
      if (parseFloat(this.form.campaignBudget) <= 0) {
        return this.$t('campaignPage.createCampaign.campaignBudget.budgetPositive');
      }
      return this.$t('campaignPage.createCampaign.campaignBudget.budgetRequired');
    },
    budgetState() {
      return this.form.campaignBudget === null || this.form.campaignBudget > 0
        || (this.form.campaignBudget?.length > 0 && parseFloat(this.form.campaignBudget) > 0);
    },
  },

  mounted() {
    this.getInfo();
  },

  methods: {
    ...mapActions('market', ['getCampaignInfo', 'getCouponDuration', 'getCouponClass']),
    async getInfo() {
      const mmcStoreInfo = await checkStoreExisting();
      const isFraudStore = !(mmcStoreInfo?.mmc_api_store?.storeStatus?.status
        === MmcStoreStatus.APPROVE);
      if (isFraudStore) {
        return;
      }
      this.init();
      this.isBannerShow();
      this.getPaymentInfo();
      this.products.forEach((product) => {
        const priceNumber = parseFloat(product.price);
        product.price = priceNumber.toFixed(2);
      });
    },
    async init() {
      await this.getCampaignInfo();
      this.form.campaignName = this.campaignName;
      this.form.campaignStatus = this.campaignStatus !== CampaignPaused;
      this.form.campaignBudget = this.dailyBudget === 0 ? 30 : this.dailyBudget;
      this.form.startDate = this.startDate !== null ? this.startDate : this.form.startDate;
      this.form.endDate = this.endDate !== null ? this.endDate : this.form.endDate;
      if (this.endDate !== null) {
        this.isEndDateEditable = true;
        this.form.isNoEndDate = false;
      }
    },
    async onClickSave() {
      let campagimInfo = {};
      const startDate = new Date(this.form.startDate).toISOString().slice(0, 10);
      let endDate = null;
      if (this.form.isNoEndDate) {
        endDate = new Date(9999, 11, 30);
        campagimInfo.end_date = endDate.toISOString().slice(0, 10);
      } else {
        endDate = new Date(this.form.endDate);
        campagimInfo.end_date = endDate.toISOString().slice(0, 10);
      }
      campagimInfo = {
        store_domain: window.contextPsAccounts.currentShop.uuid,
        name: this.form.campaignName,
        is_enabled: this.form.campaignStatus,
        daily_budget: this.form.campaignBudget,
        sales_country_code: window.country_iso_code,
        start_date: startDate,
        end_date: endDate,
      };
      this.saveLoading = true;
      try {
        await upsertCampaign(campagimInfo);
        window.location.reload();
      } catch {
        this.saveLoading = false;
      }
    },
    onClickCancel() {
      if (this.campaignId === 0) {
        this.$router.push({ name: 'overview' });
      } else {
        const flag = true;
        this.$emit('editCampaign', flag);
      }
    },
    onEnableEndDate() {
      this.isEndDateEditable = true;
    },
    onDisableEndDate() {
      this.form.endDate = null;
      this.isEndDateEditable = false;
    },
    onClickNaviItem(name) {
      this.currentPreview = name;
    },
    async isBannerShow() {
      const accountInfo = await getAccountStatus();
      this.email = accountInfo.signed_up_email;
      this.accountId = accountInfo.bingads_account.AccountId;
      this.customerId = accountInfo.bingads_account.CustomerId;
      if (accountInfo.bingads_account_status
        === accountStatus.SIGN_UP_INVITATION_SENT_NOT_ACCEPTED) {
        this.isConnect = false;
        this.isConfirmed = false;
      } else if (accountInfo.bingads_account_status === accountStatus.SIGNED_UP_NOT_CONNECTED) {
        this.isConnect = false;
        this.isConfirmed = true;
      } else {
        if (this.couponDuration === null) {
          await this.getCouponDuration();
        }
        if (this.couponDuration >= 0 && this.couponDuration <= 30) {
          await this.getCouponClass();
          this.isCouponAvailable = true;
        }
      }
      this.isFetchConnect = true;
    },
    async resendEmail() {
      // eslint-disable-next-line camelcase
      const { signup_invitation_sent_limited } = await resendEmail();
      let content = this.$t('campaignPage.banner.confirmEmail.resendSucceed');
      let variant = 'success';
      let title = this.$t('general.errorTitle.succeed');
      // eslint-disable-next-line camelcase
      if (signup_invitation_sent_limited) {
        content = this.$t('general.errorMap.SignUpInvitationSentLimited');
        variant = 'danger';
        title = this.$t('general.errorTitle.error');
      }
      window.$vue.$bvToast.toast(content, {
        toaster: 'b-toaster-bottom-center',
        noCloseButton: true,
        title,
        toastClass: 'fluent-toast resendEmail',
        solid: true,
        static: true,
        variant,
      });
    },
    async getPaymentInfo() {
      const paymentInfo = await getPaymentInfo();
      this.paymentExist = paymentInfo.is_payment_setup;
      this.currency = paymentInfo.currency_code;
      this.isFetchPayment = true;
    },
  },
};
</script>

