<template>
  <div>
    <div class="ms-ps-title">
      {{ $t('configurations.attributesMappingPage.title') }}
    </div>
    <div style="margin-bottom:32px;margin-top:24px">
      {{ $t('configurations.attributesMappingPage.description') }}
      <a target="_blank" href="https://help.ads.microsoft.com/#apex/ads/en/51084">
        {{ $t('configurations.attributesMappingPage.descriptionLink') }}
      </a>
    </div>
    <attributes-mapping-form ref="AttributesMappingForm" />
    <div style="margin-top: 44px; padding-bottom: 200px;">
      <f-button
        variant="primary"
        :loading="finishLoading"
        style="margin-right: 16px"
        :disabled="finishDisable"
        @click="onFinish"
      >
        {{ $t('general.buttons.finish') }}
      </f-button>
      <f-button variant="outline-secondary" :loading="backLoading" @click="onBack">
        {{ $t('general.buttons.back') }}
      </f-button>
    </div>
    <f-modal
      :visible="modalVisible"
      :title="$t('configurations.attributesMappingPage.existWarnings.title')"
      :modal-style="{width:'896px'}"
      :primary-button-name="$t('general.buttons.finish')"
      :primary-loading="finishModalLoading"
      @secondaryAction="onHideModal"
      @primaryAciton="onClickSave"
      @close="onHideModal"
    >
      <div>
        <span>
          {{ $t('configurations.attributesMappingPage.existWarnings.description.beforeLink') }}
        </span>
        <a target="_blank" href="https://help.ads.microsoft.com/#apex/ads/en/51084">
          {{ $t('configurations.attributesMappingPage.existWarnings.description.link') }}
        </a>
        <span>
          {{ $t('configurations.attributesMappingPage.existWarnings.description.afterLink') }}
        </span>
      </div>
      <div class="radio-subtitle">
        {{ $t('configurations.attributesMappingPage.existWarnings.subtitle') }}
      </div>
      <div style="margin-bottom: 40px">
        <b-form-radio
          v-for="item in radioOptions"
          :key="item.text" v-model="radioSelected"
          :value="item.value"
          style="margin-bottom: 32px"
        >
          {{ item.text }}
        </b-form-radio>
      </div>
    </f-modal>
  </div>
</template>

<script>
import { mapState } from 'vuex';
import {
  RequiredAttributes, OptionalAttributes, ExistRadiosAttributes, NotAvailableValue,
} from '../../models/enums/Microsoft-product-attributes';
import { upsertAndLinkStore } from '../../services/bingads.service';
import AttributesMappingForm from '../../components/overview/AttributesMappingForm.vue';

export default {
  name: 'MappingAttributesSection',
  components: { AttributesMappingForm },
  data() {
    return {
      RequiredAttributes,
      OptionalAttributes,
      finishLoading: false,
      modalVisible: false,
      finishModalLoading: false,
      mmcStoreInfo: {},
      radioSelected: ExistRadiosAttributes[0],
      radioOptions: [
        { text: this.$t('configurations.attributesMappingPage.existWarnings.radioGroup.notExist'), value: ExistRadiosAttributes[0] },
        { text: this.$t('configurations.attributesMappingPage.existWarnings.radioGroup.exist'), value: ExistRadiosAttributes[1] },
      ],
      backLoading: false,
    };
  },
  computed: {
    ...mapState({
      storeName: (state) => state.mmcStore.storeName,
      marketCode: (state) => state.mmcStore.marketCode,
      shippingRate: (state) => state.mmcStore.shippingRate,
      finishDisable: (state) => state.mmcStore.finishDisable,
    }),
  },
  methods: {
    async finishBase() {
      try {
        await upsertAndLinkStore(this.mmcStoreInfo);
        if (this.modalVisible === true) {
          this.modalVisible = false;
          this.finishModalLoading = false;
        }
        const redirectUrl = window.contextPsAccounts.currentShop.url;
        window.location.href = redirectUrl;
      } catch {
        this.finishLoading = false;
        this.finishModalLoading = false;
      }
    },
    async onFinish() {
      this.finishLoading = true;
      this.mmcStoreInfo = {};
      const { contextPsAccounts } = window;
      this.mmcStoreInfo.shipping_rate = this.shippingRate;
      const fieldMapping = {};
      let isModalVisible = false;
      const { selectedRequiredFields } = this.$refs.AttributesMappingForm;
      const { selectedOptionalFields } = this.$refs.AttributesMappingForm;
      RequiredAttributes.forEach((requiredAttribute, index) => {
        if (selectedRequiredFields[index] !== NotAvailableValue[0]) {
          fieldMapping[requiredAttribute] = selectedRequiredFields[index];
        } else {
          isModalVisible = true;
        }
      });
      OptionalAttributes.forEach((optionalattribute, index) => {
        if (selectedOptionalFields[index] !== NotAvailableValue[0]) {
          fieldMapping[optionalattribute] = selectedOptionalFields[index];
        }
      });
      this.mmcStoreInfo.field_mapping = fieldMapping;
      this.mmcStoreInfo.tenant_id = 5;
      this.mmcStoreInfo.store_domain = window.contextPsAccounts.currentShop.uuid;
      this.mmcStoreInfo.user_email = contextPsAccounts.user.email;
      this.mmcStoreInfo.user_name = window.employeeName.firstName + window.employeeName.lastName;
      this.mmcStoreInfo.market = this.marketCode;
      this.mmcStoreInfo.technical_contact_email = contextPsAccounts.user.email;
      this.mmcStoreInfo.store_name = this.storeName;
      this.mmcStoreInfo.if_store_exists = null;
      this.mmcStoreInfo.shop_id = window.contextPsAccounts.currentShop.id;
      this.mmcStoreInfo.store_url = window.shopUrlForMicrosoft;
      this.mmcStoreInfo.shop_domain = window.contextPsAccounts.currentShop.domain;
      if (isModalVisible === true) {
        this.modalVisible = true;
        this.finishLoading = false;
      } else {
        await this.finishBase();
      }
    },
    onBack() {
      this.backLoading = true;
      const { selectedRequiredFields } = this.$refs.AttributesMappingForm;
      const { selectedOptionalFields } = this.$refs.AttributesMappingForm;
      this.$store.commit('mmcStore/SAVE_REQUIRED_ATTRIBUTES', selectedRequiredFields);
      this.$store.commit('mmcStore/SAVE_OPTIONAL_ATTRIBUTES', selectedOptionalFields);
      this.$router.push({ name: 'setup-mmc-store' });
    },
    async onClickSave() {
      this.finishModalLoading = true;
      await this.finishBase();
    },
    onHideModal() {
      this.modalVisible = false;
      this.finishModalLoading = false;
    },
  },
};
</script>

<style scoped lang="scss">

.button-subtitle {
  font-weight: 600;
  margin-bottom: 24px;
  margin-top: 32px
}

.radio-subtitle {
  font-weight: 600;
  margin-bottom: 24px;
  margin-top: 32px;
}

