<template>
  <div class="toggle">
    <span
      class="toggle__title"
      :class="{'toggle__title--disabled': disabled}"
    >
      <slot>{{ label }}</slot>
    </span>

    <label class="toggle__wrapper" for="switch">
      <input
        id="switch"
        class="toggle__input"
        type="checkbox"
        :checked="checked"
        :disabled="disabled"
        v-bind="$attrs"
        @change="toggle"
      >
      <span class="toggle__switch" />
      <span class="toggle__text toggle__text--off">{{ labelOff }}</span>
      <span class="toggle__text toggle__text--on">{{ labelOn }}</span>
    </label>
  </div>
</template>

<script>

export default {
  name: 'FluentSwitch',

  model: {
    prop: 'checked',
    event: 'change',
  },
  props: {
    label: {
      type: String,
      default: 'Toggle',
    },
    labelOff: {
      type: String,
      default: 'Off',
    },
    labelOn: {
      type: String,
      default: 'On',
    },
    checked: {
      type: Boolean,
      default: false,
    },
    disabled: {
      type: Boolean,
      default: false,
    },
  },

  methods: {
    toggle() {
      if (!this.disabled) {
        this.$emit('change', !this.checked);
      }
    },
  },
};
</script>

<style lang="scss">

.toggle {
  font-family: 'Segoe UI';
  font-size: 15px;
  margin: 8px 0;
}
.toggle__title {
  display: block;
  line-height: 30px;
  margin-bottom: 4px;
  &--disabled {
    color: #999;
  }
}
.toggle__wrapper {
  display: inline-flex !important;
  align-items: center;
  position: relative;
}
.toggle__input {
  position: absolute;
  visibility: hidden;
  &:checked + .toggle__switch {
    background: var(--accent-color, #0078d7);
    border-color: var(--accent-color, #0078d7);
    &:after {
      background: #fff;
      left: 27px
    }
  }
  &:disabled + .toggle__switch {
    background: #ccc;
    border-color: #ccc;
    &:after {
      background: #a3a3a3;
    }
  }
}
.toggle__switch {
  background: transparent;
  border: 1px solid #333;
  border-radius: 16px;
  box-sizing: border-box;
  width: 48px;
  height: 24px;
  position: relative;
  display: block;
  flex: 0 0 auto;
  &:after {
    content: '';
    width: 16px;
    height: 16px;
    position: absolute;
    top: 3px;
    left: 3px;
    background: #333;
    border-radius: 50%;
    transition: left 0.4s ease;
  }
}
.toggle__text {
  padding: 0 9px;
  color: #000100;
  line-height: 20px;
  display: block;
  .toggle__input:disabled ~ & {
    color: #999;
  }
  &--on {
    display: none;
    .toggle__input:checked ~ & {
      display: block;
    }
  }
  &--off {
    display: block;
    .toggle__input:checked ~ & {
      display: none;
    }
  }
}
</style>
