<template>
  <div>
    <f-alert :show="noCampaign" variant="info" style="margin-top: 16px;">
      <div>
        {{ $t('overviewPage.campaigns.coupon.content',
              [upFrontSpending, daysToSpend, couponValue]) }}
      </div>
      <div>
        <a target="_blank" href="https://help.ads.microsoft.com/#apex/ads/en/50829/3">{{ $t('campaignPage.banner.coupon.terms') }}
        </a>
      </div>
      <div>{{ $t('overviewPage.campaigns.coupon.action') }}</div>
    </f-alert>
  </div>
</template>

<script>
import { mapActions, mapState } from 'vuex';

export default {
  data() {
    return {
      noCampaign: false,
    };
  },
  computed: {
    ...mapState({
      couponDuration: (state) => state.market.couponDuration,
      couponValue: (state) => state.market.couponValue,
      upFrontSpending: (state) => state.market.upFrontSpending,
      daysToSpend: (state) => state.market.daysToSpend,
      campaignId: (state) => state.market.campaignId,
    }),
  },
  mounted() {
    this.bannerShow();
  },
  methods: {
    ...mapActions('market', ['getCouponClass', 'getCampaignInfo']),
    async bannerShow() {
      await this.getCampaignInfo();
      if (this.campaignId === 0) {
        this.noCampaign = true;
      }
      console.log(this.noCampaign);
      await Promise.all([
        this.getCouponClass(),
      ]);
    },
  },
};
</script>

