<template>
  <div>
    <div id="feedback-footer">
      <span>{{ $t("overviewPage.feedback.description") }}</span>
      <a target="_blank" href="https://addons.prestashop.com/ratings.php">{{ $t("overviewPage.feedback.goodLink") }}</a>
      <img src="@/assets/image/happy-face.svg">
      <a @click="showModal" @keydown="() => { }">
        {{ $t("overviewPage.feedback.badLink") }}
      </a>
      <img src="@/assets/image/sad-face.svg">
    </div>

    <!-- use the modal component, pass in the prop -->
    <!-- eslint-disable-->
    <f-modal :visible="modalVisible" :title="$t('overviewPage.feedbackModal.title')" :modal-style="{ width: '800px' }"
      :primary-loading="loading" :primary-button-name="$t('general.buttons.submit')" :button-disabled="submitDisable"
      @secondaryAction="onHideModal" @primaryAciton="onSaveFeedback" @close="onHideModal">
      <div>{{ $t("overviewPage.feedbackModal.description") }}</div>
      <b-form style="margin-top: 24px; width: 72%" @submit="onSaveFeedback">
        <div style="margin-bottom: 8px; font-weight: 600;">
          {{ $t("overviewPage.feedbackModal.formLabels.issue") }}
        </div>
        <!-- eslint-disable-next-line-->
        <b-form-select v-model="form.issue" :options="issues" style="margin-bottom: 16px" />
        <b-form-group id="input-group-2" label-for="input-2" :label="$t('overviewPage.feedbackModal.formLabels.advise')">
          <b-form-input id="input-2" v-model="form.advise" :placeholder="
            $t('overviewPage.feedbackModal.formPlaceholders.advise')
          " required />
        </b-form-group>
        <b-form-group id="input-group-3" label-for="input-3"
          :label="$t('overviewPage.feedbackModal.formLabels.emailAddress')">
          <b-form-input id="input-3" v-model="form.emailAddress" :placeholder="
            $t('overviewPage.feedbackModal.formPlaceholders.emailAddress')
          " required />
        </b-form-group>
        <b-form-group id="input-group-4" label-for="input-4"
          :label="$t('overviewPage.feedbackModal.formLabels.phoneNumber')">
          <b-form-input id="input-4" v-model="form.phoneNumber" :placeholder="
            $t('overviewPage.feedbackModal.formPlaceholders.phoneNumber')
          " required />
        </b-form-group>
      </b-form>

      <span>
        {{ $t("overviewPage.feedbackModal.contact.lookingForSupport") }}
        <a target="_blank" href="https://about.ads.microsoft.com/en-us/microsoft-advertising-support">
          {{ $t('overviewPage.feedbackModal.contact.contactMicrosoftSupportLink') }}
        </a>
      </span>
    </f-modal>
  </div>
</template>

<script>
import { saveFeedback, getFeedbackCategory } from '../../services/bingads.service';

export default {
  data() {
    return {
      modalVisible: false,
      issues: [],
      form: {
        issue: null,
        advise: null,
        emailAddress: null,
        phoneNumber: null,
      },
      loading: false,
    };
  },
  computed: {
    submitDisable() {
      const values = Object.values(this.form);
      return values.some((x) => x === null || x.trim() === '');
    },
  },
  methods: {
    async showModal() {
      const data = [
        ['Store Rejection', this.$t('overviewPage.feedbackModal.issueCatalog.storeRejection')],
        ['Offer Rejections', this.$t('overviewPage.feedbackModal.issueCatalog.offerRejections')],
        ['Catalog Sync', this.$t('overviewPage.feedbackModal.issueCatalog.catalogSync')],
        ['Account Setup', this.$t('overviewPage.feedbackModal.issueCatalog.accountSetup')],
        ['Campaigns', this.$t('overviewPage.feedbackModal.issueCatalog.campaigns')],
        ['Billing', this.$t('overviewPage.feedbackModal.issueCatalog.billing')],
        ['Performance', this.$t('overviewPage.feedbackModal.issueCatalog.performance')],
        ['Other', this.$t('overviewPage.feedbackModal.issueCatalog.other')],
      ];
      await getFeedbackCategory();
      this.modalVisible = true;
      this.form.issue = null;
      this.form.advise = null;
      this.form.emailAddress = null;
      this.form.phoneNumber = null;
      this.issues = [];
      data.forEach((category) => {
        const value = category[0];
        const text = category[1];
        if (this.form.issue === null) {
          this.form.issue = value;
        }
        const issuesInfo = { value, text };
        this.issues.push(issuesInfo);
      });
    },
    onHideModal() {
      this.modalVisible = false;
    },
    async onSaveFeedback() {
      this.loading = true;
      const saveFeedbackInfo = {
        tenant_id: 0,
        store_domain: window.contextPsAccounts.currentShop.uuid,
        category: this.form.issue,
        feedback: this.form.advise,
        email: this.form.emailAddress,
        phone_num: this.form.phoneNumber,
      };
      try {
        await saveFeedback(saveFeedbackInfo);
        this.modalVisible = false;
      } finally {
        this.loading = false;
      }
    },
  },
};
</script>

