<template>
  <section-card :title="$t('overviewPage.titles.campaigns')">
    <template #body>
      <div id="metric-list">
        <div v-for="(metric, index) in metrics" :key="index" class="metric-block">
          <div class="title">
            {{ metric }}
          </div>
          <div class="value">
            {{ values[index] }}
          </div>
        </div>
      </div>
    </template>
    <template #buttons>
      <b-button variant="outline-secondary" @click="onClickViewCampaigns">
        {{ $t('overviewPage.campaigns.buttons.viewCampaigns') }}
      </b-button>
    </template>
  </section-card>
</template>

<script>
import SectionCard from './SectionCard.vue';
import { GetLatestCampaignReportSummary, getPaymentInfo } from '../../services/bingads.service';

export default {
  name: 'HasCampaignsSectionCard',
  components: {
    SectionCard,
  },
  data() {
    return {
      metrics: [
        this.$t('overviewPage.campaigns.metricTitles.clicks'),
        this.$t('overviewPage.campaigns.metricTitles.conversions'),
        this.$t('overviewPage.campaigns.metricTitles.spends'),
        this.$t('overviewPage.campaigns.metricTitles.impressions'),
      ],
      values: ['-', '-', '-', '-'],
      currencySymbol: null,
    };
  },
  mounted() {
    this.getLatestCampaignReportSummary();
  },
  methods: {
    onClickViewCampaigns() {
      this.$router.push({ name: 'campaigns' });
    },
    async getLatestCampaignReportSummary() {
      const [metricsInfo, paymentInfo] = await Promise.all([
        GetLatestCampaignReportSummary(30),
        getPaymentInfo(),
      ]);
      this.values = [metricsInfo.Clicks,
        metricsInfo.Conversions,
        paymentInfo.currency_symbol + metricsInfo.Cost.toFixed(2),
        metricsInfo.Impressions];
    },
    async getPaymentInfo() {
      const paymentInfo = await getPaymentInfo();
      this.currencySymbol = paymentInfo.currency_symbol;
    },
  },
};
</script>

