<template>
  <skeletion-card v-if="isLoading" :title="$t('overviewPage.titles.campaigns')" />
  <div v-else>
    <has-campaigns-section-card-vue v-if="hasCampaign" />
    <no-campaigns-section-card-vue v-else />
  </div>
</template>

<script>
import HasCampaignsSectionCardVue from './HasCampaignsSectionCard.vue';
import NoCampaignsSectionCardVue from './NoCampaignsSectionCard.vue';
import { getCampaignInfo } from '../../services/bingads.service';
import SkeletionCard from './SkeletionCard.vue';

export default {
  name: 'CampaignsSectionCard',
  components: {
    HasCampaignsSectionCardVue,
    NoCampaignsSectionCardVue,
    SkeletionCard,
  },
  data() {
    return {
      isLoading: true,
      hasCampaign: false,
    };
  },
  mounted() {
    this.getCampaignInfo();
  },
  methods: {
    async getCampaignInfo() {
      const campaignInfo = await getCampaignInfo();
      this.hasCampaign = campaignInfo.campaign_id !== 0;
      this.isLoading = false;
    },
  },
};
</script>

