<template>
  <div>
    <div class="ms-ps-title">
      {{ $t('configurations.selectMicrosoftAdsAccountPage.title') }}
    </div>
    <div class="ms-ps-subtitle">
      {{ $t('configurations.selectMicrosoftAdsAccountPage.subtitle') }}
    </div>

    <div id="select-group">
      <b-form-select v-model="customer" :options="customers" @change="onChangeAccounts" />
      <b-form-select v-model="account" :options="accounts" />
    </div>
    <div style="margin-top: 44px;">
      <f-button
        variant="primary"
        style="margin-right: 12px"
        :disabled="isSelected"
        :loading="loading"
        @click="onClickSignIn"
      >
        {{ $t('general.buttons.continue') }}
      </f-button>
      <f-button variant="outline-secondary" @click="onClickCancel">
        {{ $t('general.buttons.cancel') }}
      </f-button>
    </div>
    <f-modal
      :visible="modalVisible"
      :title="$t('configurations.selectMicrosoftAdsAccountPage.modalTitle')"
      :modal-style="{ width: '680px' }"
      :primary-button-name="$t('configurations.selectMicrosoftAdsAccountPage.cancel')"
      :secondary-button-name="$t('configurations.selectMicrosoftAdsAccountPage.connectAnyway')"
      :secondary-loading="modalLoading"
      @primaryAciton="onHideModal"
      @secondaryAction="onModalConnect"
      @close="onHideModal"
    >
      <div>
        {{ $t('configurations.selectMicrosoftAdsAccountPage.content1') }}
        <br>
        <br>
        {{ $t('configurations.selectMicrosoftAdsAccountPage.content2') }}
      </div>
    </f-modal>
  </div>
</template>

<script>
import { getMutipleAccounts, connectMicroSoftAds, connectOverride } from '../../services/bingads.service';
import config from '../../config';

export default {
  data() {
    return {
      customer: null,
      account: null,
      loading: false,
      customers: [{
        value: null, text: this.$t('configurations.selectMicrosoftAdsAccountPage.placeholders.customer'), disabled: true,
      }],
      accountDefault: { value: null, text: this.$t('configurations.selectMicrosoftAdsAccountPage.placeholders.account'), disabled: true },
      accounts: [],
      customerAccountInRecord: null,
      modalVisible: false,
      modalLoading: false,
    };
  },
  computed: {
    isSelected() {
      return this.customer === null || this.account === null;
    },
  },
  async mounted() {
    this.accounts = [this.accountDefault];
    const data = await getMutipleAccounts();
    const adsCustomers = data.bingads_customer_accounts;
    this.customerAccountInRecord = data.bingads_customer_account_in_record;
    adsCustomers.forEach((customer) => {
      const customerInfo = { value: customer, text: customer.CustomerName };
      this.customers.push(customerInfo);
    });
  },
  methods: {
    async onClickSignIn() {
      try {
        this.loading = true;
        const requestBody = {
          tenant_id: config.tenantId,
          store_domain: window.contextPsAccounts.currentShop.uuid,
          customer_id: this.customer.CustomerId,
          account_id: this.account.AccountId,
          account_name: this.account.AccountName,
        };
        // if customerAccountInRecord is not empty, need to connectoverride
        // becase customer sign in diff ms account.
        if (this.customerAccountInRecord !== null) {
          this.modalVisible = true;
        } else {
          await connectMicroSoftAds(requestBody);
          this.$router.push({ name: 'setup-mmc-store' });
        }
      } catch {
        this.loading = false;
      }
    },
    onClickCancel() {
      const redirectUrl = window.contextPsAccounts.currentShop.url;
      window.location.href = redirectUrl;
    },
    onChangeAccounts() {
      const accountsOfCustomer = this.customer.Accounts;
      this.accounts = [this.accountDefault];
      this.account = null;
      accountsOfCustomer.forEach((acc) => {
        const accountInfo = { value: acc, text: acc.AccountName };
        this.accounts.push(accountInfo);
      });
    },
    onHideModal() {
      this.loading = false;
      this.modalVisible = false;
    },
    async onModalConnect() {
      try {
        this.modalLoading = true;
        const requestBody = {
          tenant_id: config.tenantId,
          store_domain: window.contextPsAccounts.currentShop.uuid,
          customer_id: this.customer.CustomerId,
          account_id: this.account.AccountId,
          account_name: this.account.AccountName,
        };
        const oldCustomerId = this.customerAccountInRecord.CustomerId;
        const oldAccountId = this.customerAccountInRecord.AccountId;
        const newCustomerId = requestBody.customer_id;
        const newAccountId = requestBody.account_id;
        requestBody.customer_id = oldCustomerId;
        requestBody.account_id = oldAccountId;
        requestBody.customer_id_new = newCustomerId;
        requestBody.account_id_new = newAccountId;
        requestBody.account_name_new = this.account.AccountName;
        await connectOverride(requestBody);
        this.$router.push({ name: 'setup-mmc-store' });
      } catch {
        this.modalLoading = false;
      }
    },
  },
};
</script>

<style lang="scss" scoped>
#select-group {
  width: 50%;
  margin-top: 8px;
}
#select-group > select {
  margin-top: 24px;
}
</style>
