<template>
  <div>
    <div class="ms-ps-title">
      {{ $t('configurations.createMicrosoftAdsAccountPage.title') }}
    </div>
    <div v-if="isIncomplete" style="margin-top: 24px">
      {{ $t('configurations.createMicrosoftAdsAccountPage.subtitle') }}
    </div>
    <b-form style="margin-top: 24px; width: 72%" @submit="onSignUp">
      <b-form-group
        id="input-group-1"
        :label="$t('configurations.createMicrosoftAdsAccountPage.formLabels.firstName')"
        label-for="input-1"
        :invalid-feedback="nameFeedback"
        :state="firstNameState"
      >
        <b-form-input
          id="input-1"
          v-model="form.firstName"
          :placeholder="$t('configurations.createMicrosoftAdsAccountPage.placeholders.firstName')"
          :state="firstNameState"
        />
      </b-form-group>

      <b-form-group
        id="input-group-2"
        :label="$t('configurations.createMicrosoftAdsAccountPage.formLabels.lastName')"
        label-for="input-2"
        :invalid-feedback="nameFeedback"
        :state="lastNameState"
      >
        <b-form-input
          id="input-2"
          v-model="form.lastName"
          :placeholder="$t('configurations.createMicrosoftAdsAccountPage.placeholders.lastName')"
          :state="lastNameState"
        />
      </b-form-group>

      <b-form-group
        id="input-group-3"
        :label="$t('configurations.createMicrosoftAdsAccountPage.formLabels.accountEmail')"
        label-for="input-3"
        :description="$t('configurations.createMicrosoftAdsAccountPage.hints.email')"
        :invalid-feedback="emailFeedback"
        :state="emailState"
      >
        <b-form-input
          id="input-3"
          v-model="form.email"
          :placeholder="$t('configurations.createMicrosoftAdsAccountPage.placeholders.email')"
          type="email"
          :state="emailState"
        />
      </b-form-group>

      <b-form-group
        id="input-group-4"
        :label="$t('configurations.createMicrosoftAdsAccountPage.formLabels.bussinessAddress')"
        label-for="input-4"
        :invalid-feedback="businessAddressFeedback"
        :state="businessAddressState"
      >
        <b-form-input
          id="input-4"
          v-model="form.businessAddress"
          :placeholder="$t('configurations.createMicrosoftAdsAccountPage.placeholders.address')"
          :state="businessAddressState"
        />
      </b-form-group>

      <b-form-group
        id="input-group-5"
        :label="$t('configurations.createMicrosoftAdsAccountPage.formLabels.city')"
        label-for="input-5"
        :invalid-feedback="cityFeedback"
        :state="cityState"
      >
        <b-form-input
          id="input-5"
          v-model="form.city"
          :placeholder="$t('configurations.createMicrosoftAdsAccountPage.placeholders.city')"
          :state="cityState"
        />
      </b-form-group>

      <b-form-group
        id="input-group-6"
        :label="$t('configurations.createMicrosoftAdsAccountPage.formLabels.stateOrProvince')"
        label-for="input-6"
        :invalid-feedback="stateOrProvinceFeedback"
        :state="stateOrProvinceState"
      >
        <b-form-input
          id="input-6"
          v-model="form.state"
          :placeholder="$t('configurations.createMicrosoftAdsAccountPage.placeholders.state')"
          :state="stateOrProvinceState"
        />
      </b-form-group>

      <b-form-group
        id="input-group-7"
        :label="$t('configurations.createMicrosoftAdsAccountPage.formLabels.postalCode')"
        label-for="input-7"
        :invalid-feedback="postalCodeFeedback"
        :state="postalCodeState"
      >
        <b-form-input
          id="input-7"
          v-model="form.postalCode"
          :placeholder="$t('configurations.createMicrosoftAdsAccountPage.placeholders.postalCode')"
          :state="postalCodeState"
        />
      </b-form-group>
      <div style="margin-bottom: 8px; font-weight: 600">
        {{ $t('configurations.createMicrosoftAdsAccountPage.formLabels.country') }}
      </div>
      <b-form-select
        v-model="form.country"
        :options="country"
        :state="countryState"
      />
      <div v-if="isCountryValid==false" id="country-feedback">
        {{ $t('configurations.createMicrosoftAdsAccountPage.warnings.invalidCountry') }}
      </div>
      <b-form-group
        id="input-group-8"
        :label="$t('configurations.createMicrosoftAdsAccountPage.formLabels.vat')"
        label-for="input-8"
        :invalid-feedback="vatFeedback"
        :state="vatState"
        style="margin-top: 16px"
        v-show = "form.country === 'PT'"
      >
        <b-form-input
          id="input-8"
          v-model="form.vat"
          :placeholder="$t('configurations.createMicrosoftAdsAccountPage.placeholders.vat')"
          :state="vatState"
        />
      </b-form-group>
      <div class="form-select">
        {{ $t('configurations.createMicrosoftAdsAccountPage.formLabels.language') }}
      </div>
      <b-form-select
        v-model="form.language"
        :options="language"
      />
      <div class="form-select">
        {{ $t('configurations.createMicrosoftAdsAccountPage.formLabels.currency') }}
      </div>
      <b-form-select
        v-model="form.currency"
        :options="currency"
      />
      <div id="hint">
        {{ $t('configurations.createMicrosoftAdsAccountPage.hints.languageAndCurrency') }}
        <a target="_blank" :href="linkUrl" class="link">
          {{ $t('configurations.createMicrosoftAdsAccountPage.hints.languageAndCurrencyLink') }}
        </a>
      </div>
      <f-button
        style="margin: 32px 0;"
        variant="primary"
        :loading="loading"
        :disabled="signUpDisabled"
        @click="onSignUp"
      >
        {{ $t('general.buttons.signUp') }}
      </f-button>
    </b-form>
  </div>
</template>

<script>

import { mapState } from 'vuex';
import CountryCodesAttributes from '../../models/enums/country-code';
import AddressStatus from '../../models/enums/address-status';
import ErrorCode from '../../models/enums/error-code';
import { signUp, validateAddress } from '../../services/bingads.service';
import config from '../../config';

export default {
  data() {
    const language = [];
    window.languages.forEach((languageItem) => {
      const languageInfo = { value: languageItem.iso_code, text: languageItem.name };
      language.push(languageInfo);
    });
    const currency = [];
    window.currencies.forEach((currencyItem) => {
      const currencyInfo = { value: currencyItem.iso_code, text: currencyItem.name };
      currency.push(currencyInfo);
    });
    const country = [];
    Object.entries(CountryCodesAttributes).forEach((x) => {
      const countryInfo = { value: x[0], text: x[1] };
      country.push(countryInfo);
    });
    country.push({
      value: null, text: this.$t('configurations.createMicrosoftAdsAccountPage.placeholders.country'), disabled: true,
    });
    const shopUrl = window.contextPsAccounts.currentShop.url;
    // eslint-disable-next-line no-underscore-dangle
    const pageToken = window._token;
    const linkUrl = `${shopUrl.substring(0, shopUrl.indexOf('?controller'))}/improve/design/cms-pages/?_token${pageToken}`;
    return {
      form: {
        firstName: window.employeeName?.firstName,
        lastName: window.employeeName?.lastName,
        email: window.contextPsAccounts.superAdminEmail,
        businessAddress: window.contact?.SHOP_ADDR1 === '' ? null : window.contact?.SHOP_ADDR1,
        city: window.contact?.SHOP_CITY === '' ? null : window.contact?.SHOP_CITY,
        state: window.contact?.SHOP_STATE === '' ? null : window.contact?.SHOP_STATE,
        postalCode: window.contact?.SHOP_CODE === '' ? null : window.contact?.SHOP_CODE,
        country: window.contact?.SHOP_COUNTRY === '' ? null : window.contact?.SHOP_COUNTRY,
        language: window.languages?.length > 0 ? window.languages[0].iso_code : null,
        currency: window.currencies?.length > 0 ? window.currencies[0].iso_code : null,
        vat: null,
      },
      language,
      currency,
      country,
      validateStates: {
        businessAddress: true,
        city: true,
        state: true,
        postalCode: true,
        country: true,
        vat: true,
      },
      suggestions: {
        businessAddress: null,
        city: null,
        state: null,
        postalCode: null,
        country: null,
        vat: null,
      },
      loading: false,
      linkUrl,
      isCountryValid: true,
    };
  },
  computed: {
    ...mapState({
      tokenPsAccounts: (state) => state.accounts.tokenPsAccounts,
    }),
    isIncomplete() {
      const queryString = window.location.search;
      const lowerCaseQueryString = queryString.toLowerCase();
      const urlParams = new URLSearchParams(lowerCaseQueryString);
      const message = urlParams.get('message');
      return message === 'incompleteaccount';
    },
    signUpDisabled() {
      if (this.form.country === 'PT') {
        return Object.values(this.form).some((x) => x === null || x === '');
      }
      const keys = Object.keys(this.form);
      let disabled = false;
      keys.forEach((key) => {
        if (key === 'vat') {
          return;
        }
        if (this.form[key] === null || this.form[key] === '') {
          disabled = true;
        }
      });
      return disabled;
    },
    firstNameState() {
      return this.form.firstName === null || this.form.firstName?.length > 0;
    },
    lastNameState() {
      return this.form.lastName === null || this.form.lastName?.length > 0;
    },
    emailState() {
      return this.form.email === null || this.form.email?.length > 0;
    },
    businessAddressState() {
      return (this.form.businessAddress === null || (this.form.businessAddress?.length > 0
      && this.form.businessAddress?.length <= 100)) && this.validateStates.businessAddress;
    },
    cityState() {
      return (this.form.city === null || (this.form.city?.length > 0
      && this.form.city?.length <= 35)) && this.validateStates.city;
    },
    stateOrProvinceState() {
      return (this.form.state === null || this.form.state?.length > 0)
      && this.validateStates.state;
    },
    postalCodeState() {
      return (this.form.postalCode === null || (this.form.postalCode?.length > 0
      && this.form.postalCode?.length <= 10)) && this.validateStates.postalCode;
    },
    countryState() {
      return this.validateStates.country;
    },
    vatState() {
      return (this.form.vat === null || (this.form.vat?.length === 11 && this.form.vat.startsWith('PT'))) && this.validateStates.vat;
    },
    nameFeedback() {
      return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.nameRequired');
    },
    emailFeedback() {
      return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.emailRequired');
    },
    businessAddressFeedback() {
      if (this.form.businessAddress === null) return null;
      if (this.form.businessAddress.length === 0) return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.addressRequired');
      if (this.form.businessAddress.length > 100) return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.addressLength');
      return this.suggestions.businessAddress;
    },
    cityFeedback() {
      if (this.form.city === null) return null;
      if (this.form.city.length === 0) return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.cityRequired');
      if (this.form.city.length > 35) return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.cityLength');
      return this.suggestions.city;
    },
    stateOrProvinceFeedback() {
      if (this.form.state === null) return null;
      if (this.form.state.length === 0) return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.stateRequired');
      return this.suggestions.state;
    },
    postalCodeFeedback() {
      if (this.form.postalCode === null) return null;
      if (this.form.postalCode.length === 0) return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.postalCodeRequired');
      if (this.form.postalCode.length > 10) return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.postalCodeLength');
      return this.suggestions.postalCode;
    },
    vatFeedback() {
      if (this.form.vat === null) return null;
      if (this.form.vat.length !== 11 || !this.form.vat.startsWith('PT')) return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.vatFormat');
      return this.suggestions.vat;
    },
    countryFeedback() {
      if (this.form.country === null) return null;
      if (this.form.country.length === 0) return this.$t('configurations.createMicrosoftAdsAccountPage.warnings.countryRequired');
      return CountryCodesAttributes[this.suggestions.country];
    },
  },
  mounted() {
    if (this.form.country !== null) {
      try {
        const [countryCode] = Object.entries(CountryCodesAttributes).find((x) => x[1]
        === this.form.country);
        this.form.country = countryCode;
      } catch {
        this.form.country = null;
      }
    }
  },
  methods: {
    updateStateAndSuggestion(suggestion, current, index) {
      if (suggestion !== current) {
        this.validateStates[index] = false;
        if (index === 'postalCode') {
          this.suggestions[index] = this.$t('configurations.createMicrosoftAdsAccountPage.warnings.codeNotMatch')
       + suggestion;
        } else {
          this.suggestions[index] = suggestion;
        }
      }
    },
    initValidate(flag) {
      this.validateStates.businessAddress = flag;
      this.validateStates.city = flag;
      this.validateStates.state = flag;
      this.validateStates.postalCode = flag;
      this.validateStates.country = flag;
      this.isCountryValid = true;
      this.validateStates.vat = flag;
    },
    initSuggestions() {
      this.suggestions.businessAddress = null;
      this.suggestions.city = null;
      this.suggestions.state = null;
      this.suggestions.postalCode = null;
      this.suggestions.country = null;
    },
    async validateAddressInfo(signUpInfo) {
      const addressInfo = {
        city: signUpInfo.city,
        countryCode: signUpInfo.country_code,
        line1: signUpInfo.line1,
        postalCode: signUpInfo.postal_code,
        stateOrProvince: signUpInfo.state_or_province,
        businessName: signUpInfo.business_name,
        line2: null,
        line3: null,
        line4: null,
      };
      try {
        const validate = await validateAddress(addressInfo);
        const suggestionInfo = validate.suggested_addresses;
        if (suggestionInfo === null) {
          this.initValidate(false);
          this.initSuggestions();
          this.suggestions.businessAddress = this
            .$t('configurations.createMicrosoftAdsAccountPage.warnings.addressInvalid');
        } else if (validate.status === AddressStatus.invalidWithSuggestions) {
          const suggestion = suggestionInfo[0];
          this.updateStateAndSuggestion(
            suggestion.Line1,
            addressInfo.line1,
            'businessAddress',
          );
          this.updateStateAndSuggestion(suggestion.City, addressInfo.city, 'city');
          this.updateStateAndSuggestion(
            suggestion.StateOrProvince,
            addressInfo.stateOrProvince,
            'state',
          );
          this.updateStateAndSuggestion(
            suggestion.PostalCode,
            addressInfo.postalCode,
            'postalCode',
          );
          this.updateStateAndSuggestion(
            suggestion.CountryCode,
            this.form.country,
            'country',
          );
        }
      } finally {
        this.loading = false;
      }
    },
    async onSignUp() {
      this.initValidate(true);
      const signUpInfo = {
        tenant_id: config.tenantId,
        store_domain: window.contextPsAccounts.currentShop.uuid,
        customer_name: window.contextPsAccounts.currentShop.name,
        industry: 'prestashop',
        account_name: window.contextPsAccounts.currentShop.name,
        business_name: window.contextPsAccounts.currentShop.name,
        city: this.form.city.trim(),
        line1: this.form.businessAddress.trim(),
        postal_code: this.form.postalCode.trim(),
        country_code: this.form.country,
        state_or_province: this.form.state.trim(),
        currency_code: this.form.currency,
        language: this.form.language,
        first_name: this.form.firstName.trim(),
        last_name: this.form.lastName.trim(),
        email: this.form.email.trim(),
        vat: this.form.vat,
      };
      this.loading = true;
      try {
        await signUp(signUpInfo);
        this.$router.push({ name: 'setup-mmc-store' });
      } catch (error) {
        if (error.response.data?.error.picApiPoolErrorCode === ErrorCode[0]) {
          await this.validateAddressInfo(signUpInfo);
        } else if (error.response.data?.error?.picApiPoolErrorCode
        === ErrorCode[1]) {
          this.validateStates.country = false;
          this.isCountryValid = false;
        }
        this.loading = false;
      }
    },
  },
};
</script>

<style lang="scss" scoped>
#hint {
  font-size: 11.2px;
  color: #8A8886;
  margin-top: 8px;
}

#country-feedback {
  font-size: 12px;
  color: #ea4719;
  margin-top: 4px;
}

.form-select {
  margin-top: 16px;
  margin-bottom: 8px;
  font-weight: 600;
}
</style>
