<template>
  <div>
    <f-alert :show="isBannerShow" variant="info" style="margin-top: 16px;">
      <div>
        {{ $t('campaignPage.banner.coupon.content', [upFrontSpending, daysToSpend, couponValue]) }}
      </div>
      <div>
        <a target="_blank" href="https://help.ads.microsoft.com/#apex/ads/en/50829/3">{{ $t('campaignPage.banner.coupon.terms') }}
        </a>
      </div>
      <div>{{ $t('campaignPage.banner.coupon.extra2', [couponDuration, upFrontSpending]) }}</div>
    </f-alert>
  </div>
</template>

<script>
import { mapActions, mapState } from 'vuex';

export default {
  data() {
    return {
      isBannerShow: false,
    };
  },
  computed: {
    ...mapState({
      couponDuration: (state) => state.market.couponDuration,
      couponValue: (state) => state.market.couponValue,
      upFrontSpending: (state) => state.market.upFrontSpending,
      daysToSpend: (state) => state.market.daysToSpend,
    }),
  },
  mounted() {
    this.bannerShow();
  },
  methods: {
    ...mapActions('market', ['getCouponDuration', 'getCouponClass']),
    onClickEdit() {
      const flag = false;
      this.$emit('editCampaign', flag);
    },
    onSave() { },
    async bannerShow() {
      if (this.couponDuration === null) {
        await Promise.all([
          this.getCouponDuration(),
          this.getCouponClass(),
        ]);
        if (this.couponDuration >= 0 && this.couponDuration <= this.daysToSpend) {
          this.isBannerShow = true;
        }
      }
    },
  },
};
</script>

