<template>
  <skeletion-card v-if="isLoading" :title="$t('overviewPage.titles.products')" />
  <section-card v-else :title="$t('overviewPage.titles.products')">
    <template #body>
      <div id="products-metric-list">
        <div class="products-metric-block">
          <div class="value">
            {{ listed }}
          </div>
          <div class="description">
            {{ $t('overviewPage.products.listed') }}
          </div>
        </div>
        <div class="products-metric-block">
          <div class="value">
            {{ pending }}
          </div>
          <div class="description">
            {{ $t('overviewPage.products.pending') }}
          </div>
        </div>
        <div class="products-metric-block">
          <div class="value">
            {{ issue }}
          </div>
          <div class="description">
            {{ $t('overviewPage.products.issued') }}
          </div>
        </div>
      </div>
      <p style="margin-top: 48px; color: #6D7175">
        {{ $t('overviewPage.products.processReminder') }}
      </p>
    </template>
    <template #buttons>
      <b-button variant="outline-secondary" @click="onClickViewProducts">
        {{ $t('overviewPage.products.buttons.viewProducts') }}
      </b-button>
    </template>
  </section-card>
</template>

<script>
import SectionCard from './SectionCard.vue';
import SkeletionCard from './SkeletionCard.vue';
import {
  getMmcOfferStatus,
} from '../../services/bingads.service';

export default {
  name: 'ProductsSectionCard',
  components: {
    SectionCard,
    SkeletionCard,
  },
  data() {
    return {
      listed: '/',
      pending: '/',
      issue: '/',
      isLoading: true,
    };
  },

  mounted() {
    this.getMmcOfferStatus();
  },

  methods: {
    onClickViewProducts() {
      this.$router.push({ name: 'products' });
    },
    async getMmcOfferStatus() {
      const offerStatus = await getMmcOfferStatus();
      this.listed = offerStatus.approved;
      this.pending = offerStatus.pending;
      this.issue = offerStatus.rejected;
      this.isLoading = false;
    },
  },
};
</script>

