<template>
  <div>
    <CouponRedeemedBanner />
    <div>
      <div class="section-title">
        {{ $t('campaignPage.banner.coupon.lastThirtyDays') }}
      </div>
      <div id="campaign-metric-list">
        <b-card v-for="metric in Object.keys(metrics)" :key="metric" class="metric-card">
          <div>
            <span class="metric-title">{{ metricsTitle[metric] }}</span>
            <img :id="metric" src="@/assets/image/icon-question-outline.svg">
            <b-tooltip :target="metric" placement="right">
              {{ metricsText[metric] }}
            </b-tooltip>
          </div>
          <div class="metric-value">
            {{ metrics[metric] }}
          </div>
        </b-card>
      </div>
    </div>
    <div>
      <div class="section-title">
        <div>
          {{ $t('campaignPage.banner.coupon.campaignPerformance') }}
        </div>
        <div class="metrics-dropdown">
          <img src="@/assets/image/icon-axis1.svg" style="margin-right: 8px">
          <b-form-select
            v-model="metric1"
            style="margin-right: 16px"
            :options="metricOptions"
            @change="onChangeMetric1"
          />
          <div>{{ $t('campaignPage.statistics.campaignPerformance.chartPlaceholder.vs') }}</div>
          <img src="@/assets/image/icon-axis2.svg" style="margin-left: 16px; margin-right: 8px;">
          <b-form-select
            v-model="metric2"
            :options="metricOptions"
            @change="onChangeMetric2"
          />
          <b-form-select
            v-model="period"
            style="margin-left: 16px"
            :options="periodOptions"
            @change="onChangeReport"
          />
        </div>
      </div>
      <b-overlay :show="isLoadingChart">
        <CampaignPerformanceChart
          :data="campaignChartData"
          :axis1="metric1"
          :axis2="metric2"
          :granularity="granularity"
          :start-date="startDate"
          :end-date="endDate"
        />
      </b-overlay>
    </div>

    <div id="products-issue">
      <b-button variant="link" style="margin: 48px 0 24px 0" @click="onClickEdit">
        <img class="edit-icon" src="@/assets/image/icon-edit.svg">
        <span>{{ $t('campaignPage.banner.coupon.editCampaign') }}</span>
      </b-button>
      <b-table :items="issues" :fields="CampaignChartFields" />
    </div>
  </div>
</template>

<script>
import { mapActions, mapState } from 'vuex';
import CampaignPerformanceChart from './CampaignPerformanceChart.vue';
import CouponRedeemedBanner from './CouponRedeemedBanner.vue';
import { GetLatestCampaignReportSummary, getCampaignReport, getPaymentInfo } from '../../services/bingads.service';
import { PeriodDays, Granularity, Metric } from '../../models/enums/campaign-report-period';

export default {
  components: { CampaignPerformanceChart, CouponRedeemedBanner },
  data() {
    return {
      metrics: {
        impressions: '-',
        clicks: '-',
        conversions: '-',
        revenue: '-',
        spend: '-',
      },
      metricsTitle: {
        impressions: this.$t('campaignPage.statistics.impressions'),
        clicks: this.$t('campaignPage.statistics.clicks'),
        conversions: this.$t('campaignPage.statistics.conversions'),
        revenue: this.$t('campaignPage.statistics.revenue'),
        spend: this.$t('campaignPage.statistics.spend'),
      },
      metricsText: {
        impressions: this.$t('campaignPage.popups.impressions'),
        clicks: this.$t('campaignPage.popups.clicks'),
        conversions: this.$t('campaignPage.popups.conversions'),
        revenue: this.$t('campaignPage.popups.revenue'),
        spend: this.$t('campaignPage.popups.spend'),
      },
      metric1: Metric.CLICKS,
      metric2: Metric.CONVERSIONS,
      campaignReport: null,
      modalVisible: false,
      isBannerShow: false,
      isLoadingChart: false,
      period: 7,
      periodOptions: [
        { value: PeriodDays.LAST_7_DAYS, text: this.$t('campaignPage.statistics.last7Days') }, // TODO: text need localization
        { value: PeriodDays.LAST_14_DAYS, text: this.$t('campaignPage.statistics.last14Days') },
        { value: PeriodDays.LAST_30_DAYS, text: this.$t('campaignPage.statistics.last30Days') },
        { value: PeriodDays.LAST_YEAR, text: this.$t('campaignPage.statistics.lastyear') },
      ],
      metricOptions: [
        { value: Metric.IMPRESSIONS, text: this.$t('campaignPage.statistics.impressions') }, // TODO: text need localization
        { value: Metric.CLICKS, text: this.$t('campaignPage.statistics.clicks') },
        { value: Metric.CONVERSIONS, text: this.$t('campaignPage.statistics.conversions') },
        { value: Metric.COST, text: this.$t('campaignPage.statistics.cost') },
      ],
      CampaignChartFields: [
        { key: 'campaignName', label: this.$t('campaignPage.createCampaign.campaignName.title') },
        { key: 'dailyBudget', label: this.$t('campaignPage.createCampaign.campaignBudget.title') },
        { key: 'market', label: this.$t('campaignPage.createCampaign.targetMarket.title') },
        { key: 'startDate', label: this.$t('campaignPage.createCampaign.startDate.title') },
        { key: 'endDate', label: this.$t('campaignPage.createCampaign.endDate.title') },
      ],
      currencySymbol: null,
    };
  },
  computed: {
    ...mapState({
      couponDuration: (state) => state.market.couponDuration,
      couponValue: (state) => state.market.couponValue,
      upFrontSpending: (state) => state.market.upFrontSpending,
      campaignId: (state) => state.market.campaignId,
      campaignName: (state) => state.market.campaignName,
      campaignStatus: (state) => state.market.campaignStatus,
      isuueStartDate: (state) => state.market.startDate,
      issueEndDate: (state) => state.market.endDate,
      dailyBudget: (state) => state.market.dailyBudget,
      salesCountryCode: (state) => state.market.salesCountryCode,
    }),
    issues() {
      return [{
        campaignName: this.campaignName,
        dailyBudget: this.dailyBudget,
        market: `${window.language.iso_code}-${window.defaultCountryCode}`,
        startDate: this.isuueStartDate,
        endDate: this.issueEndDate ? this.issueEndDate : this.$t('campaignPage.createCampaign.endDate.radioGroup.noEndDate'), // TODO: Need localization
      }];
    },
    campaignChartData() {
      if (this.campaignReport === null) {
        return [[], []];
      }
      const data1 = this.campaignReport.map((x) => x[this.metric1]);
      const data2 = this.campaignReport.map((x) => x[this.metric2]);
      return [data1, data2];
    },
    granularity() {
      return this.period <= 30 ? Granularity.DAILY : Granularity.MONTHLY;
    },
    startDate() {
      const startDate = new Date();
      startDate.setDate(startDate.getDate() - this.period);
      return startDate;
    },
    endDate() {
      const endDate = new Date();
      return endDate;
    },
  },
  mounted() {
    this.bannerShow();
    this.getLatestCampaignReportSummary();
    this.onChangeReport();
  },
  methods: {
    ...mapActions('market', ['getCouponDuration', 'getCouponClass']),
    onClickEdit() {
      const flag = false;
      this.$emit('editCampaign', flag);
    },
    onSave() { },
    async bannerShow() {
      await this.getCouponDuration();
      if (this.couponDuration >= 0 && this.couponDuration <= 30) {
        await this.getCouponClass();
        this.isBannerShow = true;
      }
    },
    async getLatestCampaignReportSummary() {
      const [metricsInfo, paymentInfo] = await Promise.all([
        GetLatestCampaignReportSummary(30),
        getPaymentInfo(),
      ]);
      this.metrics.impressions = metricsInfo.Impressions;
      this.metrics.clicks = metricsInfo.Clicks;
      this.metrics.conversions = metricsInfo.Conversions;
      this.metrics.revenue = paymentInfo.currency_symbol + metricsInfo.ConversionValues.toFixed(2);
      this.metrics.spend = paymentInfo.currency_symbol + metricsInfo.Cost.toFixed(2);
    },
    async onChangeReport() {
      this.isLoadingChart = true;
      const startDate = new Date();
      startDate.setDate(startDate.getDate() - this.period);
      const endDate = new Date();
      const startTimeUTC = startDate.toISOString().slice(0, 10);
      const endTimeUTC = endDate.toISOString().slice(0, 10);
      const campaignInfo = {
        params: {
          startDate: startTimeUTC,
          endDate: endTimeUTC,
          granularity: this.period <= 30 ? Granularity.DAILY : Granularity.MONTHLY,
        },
      };
      const campaignReport = await getCampaignReport(campaignInfo);
      this.isLoadingChart = false;
      this.campaignReport = campaignReport;
    },

    onChangeMetric1() {

    },
    onChangeMetric2() {

    },
    async getPaymentInfo() {
      const paymentInfo = await getPaymentInfo();
      this.currencySymbol = paymentInfo.currency_symbol;
    },
  },
};
</script>

