<template>
  <div style="height: 100%">
    <logo-banner />
    <div class="content">
      <steps-bar :steps="steps" :current-step="$route.meta.step" />
      <router-view />
    </div>
    <div class="footer">
      <img
        style="margin-right:8px; position:relative; top: -2px;"
        src="@/assets/image/icon-info-outline.svg"
      >
      <a target="_blank" href="https://about.ads.microsoft.com/en-us/microsoft-advertising-support">
        {{ $t('configurations.contactUs.link') }}
      </a>
    </div>
  </div>
</template>

<script>

import { mapState } from 'vuex';
import LogoBanner from '../../components/configuration/LogoBanner.vue';
import StepsBar from '../../components/configuration/StepsBar.vue';

export default {
  components: { LogoBanner, StepsBar },
  data() {
    return {
    };
  },
  computed: {
    ...mapState({
      accountEmail: (state) => state.accounts.accountEmail,
    }),
    steps() {
      const subtitles = [{
        title: this.$t('configurations.stepsBar.connectPsAccount'),
        subtitle: window.contextPsAccounts.user.email,
      }, {
        title: this.$t('configurations.stepsBar.storeRequirement'),
      }, {
        title: this.$t('configurations.stepsBar.connectMicrosoftAccount'),
        subtitle: this.accountEmail,
      }, {
        title: this.$t('configurations.stepsBar.syncProductsToMicrosoft'),
      }];
      return subtitles;
    },
  },
  mounted() {
  },
};
</script>

