import axios from 'axios';
import config from '../config';
import addErrorHandler from './general';

const instance = axios.create({
  baseURL: config.endpoint.bingads,
  headers: {
    Token: window.tokenPsAccounts,
  },
});

addErrorHandler(instance);

// Ads Accounts
const getAccountStatus = async () => {
  const { data } = await instance.get('AdsAccount/GetAccountStatus');
  return data;
};

const signInMSAccount = async (redirectUrl) => {
  const response = await instance.get('AdsAccount/SignInMSAccount', {
    params: {
      redirectUrl,
    },
  });
  return response.data;
};

const validateAddress = async (address) => {
  const response = await instance.get('AdsAccount/ValidateAddress', {
    params: address,
  });
  return response.data;
};

const signUp = async (signUpInfo) => {
  const response = await instance.post('AdsAccount/signUp', signUpInfo);
  return response.data;
};

const getFeedbackCategory = async () => {
  const response = await instance.get('Feedback/GetFeedbackCategory');
  return response.data;
};

const saveFeedback = async (saveFeedbackInfo) => {
  const response = await instance.post('Feedback/AddFeedback', saveFeedbackInfo);
  return response.data;
};

const getMutipleAccounts = async () => {
  const response = await instance.get('AdsAccount/GetBingAdsAcountInfo');
  return response.data;
};

const connectMicroSoftAds = async (requestbody) => {
  const response = await instance.post('AdsAccount/Connect', requestbody);
  return response.data;
};

const connectOverride = async (requestbody) => {
  const response = await instance.post('AdsAccount/ConnectOverride', requestbody);
  return response.data;
};

