import Vue from 'vue';
import VueRouter from 'vue-router';
import { checkStoreExisting, getAppSetupStatus } from '../services/bingads.service';
import Promotion from '../views/PromotionPage.vue';
import ConfigurationLayout from '../views/configure/ConfigurationLayout.vue';
import PrestaShopSetupPage from '../views/configure/PrestaShopSetupPage.vue';
import StoreRequirements from '../views/configure/StoreRequirementsPage.vue';
import ConnectMicrosoftAccount from '../views/configure/ConnectMicrosoftAccountPage.vue';
import OverviewLayout from '../views/overview/OverviewLayout.vue';
import Overview from '../views/overview/OverviewPage.vue';
import Campaigns from '../views/overview/CampaignsPage.vue';
import Products from '../views/overview/ProductsPage.vue';
import CreateMicrosoftAccount from '../views/configure/CreateMicrosoftAccountPage.vue';
import MappingProductAttributes from '../views/configure/MappingProductAttributesPage.vue';
import SetupMmcStore from '../views/configure/SetupMmcStorePage.vue';
import SelectMicrosoftAccount from '../views/configure/SelectMicrosoftAccountPage.vue';
import store from '../store';
import AppSetupStatus from '../models/enums/App-Setup-Status';
import { getData } from '../utils/local-storage';

Vue.use(VueRouter);

const checkMultiStore = (to, from, next) => {
  const queryString = window.location.search;
  const lowerCaseQueryString = queryString.toLowerCase();
  const urlParams = new URLSearchParams(lowerCaseQueryString);
  const isAutoConnected = urlParams.get('isautoconnected');
  const message = urlParams.get('message');
  if (message === 'incompleteaccount') {
    next({ name: 'create-microsoft-account' });
  }
  if (isAutoConnected === 'false') {
    next({ name: 'select-microsoft-account' });
  } else if (isAutoConnected === 'true') {
    next({ name: 'setup-mmc-store' });
  } else {
    next();
  }
};

const checkStore = async (to, from, next) => {
  const isPromotionVisited = getData('isPromotionVisited');
  if (window.contextPsAccounts?.isShopContext === false) {
    if (isPromotionVisited) {
      next({ name: 'prestashop-setup' });
    } else {
      next({ name: 'promotion' });
    }
    return;
  }
  try {
    let status = await getAppSetupStatus(window.tokenPsAccounts === null
    || !(window.contextPsAccounts.user.emailIsValidated
    || window.contextPsAccounts.user.email !== '' || window.contextPsAccounts.isShopContext)
    || !window.contextPsAccounts.psAccountsIsEnabled ? '' : window.tokenPsAccounts);
    if (status === AppSetupStatus.APP_INSTALLED && window.tokenPsAccounts !== '' && window.tokenPsAccounts !== null
      && window.contextPsAccounts.user.emailIsValidated
      && window.contextPsAccounts.user.email !== '' && window.contextPsAccounts.isShopContext
      && window.contextPsAccounts.psAccountsIsEnabled) {
      status = AppSetupStatus.PS_ACCOUNT_ASSOCIATED;
    }
    switch (status) {
      case AppSetupStatus.APP_INSTALLED:
        if (isPromotionVisited) {
          next({ name: 'prestashop-setup' });
        } else {
          next({ name: 'promotion' });
        }
        break;
      case AppSetupStatus.PS_ACCOUNT_ASSOCIATED:
        next({ name: 'store-requirements' });
        break;
      case AppSetupStatus.CHECKLIST_FINISHED:
        next({ name: 'connect-microsoft-account' });
        break;
      case AppSetupStatus.HAS_MSA_ACCOUNT:
        next({ name: 'setup-mmc-store' });
        break;
      case AppSetupStatus.BMC_SETUP:
        next({ name: 'overview' });
        break;
      default:
        next({ name: 'promotion' });
    }
  } catch {
    next({ name: 'promotion' });
  }
};

const checkMmcStoreExist = async (to, from, next) => {
  const mmcStoreInfo = await checkStoreExisting();
  const mmcApiData = mmcStoreInfo.mmc_api_store;
  if (mmcApiData != null) {
    if (mmcStoreInfo.enable_feed_download_info === true) {
      const redirectUrl = window.contextPsAccounts.currentShop.url;
      window.location.href = redirectUrl;
    } else {
      store.commit('mmcStore/SAVE_API_INFO', mmcApiData);
      next();
    }
  } else {
    next();
  }
};

const routes = [{
  path: '/promotion',
  name: 'promotion',
  component: Promotion,
}, {
  path: '/configure',
  name: 'configuration',
  redirect: '/configuration/prestashop-setup',
  component: ConfigurationLayout,
  children: [{
    path: '/configure/prestashop-setup',
    name: 'prestashop-setup',
    meta: { step: 0 },
    component: PrestaShopSetupPage,
  }, {
    path: '/configure/store-requirements',
    name: 'store-requirements',
    meta: { step: 1 },
    component: StoreRequirements,
  }, {
    path: '/configure/connect-microsoft-account',
    name: 'connect-microsoft-account',
    meta: { step: 2 },
    component: ConnectMicrosoftAccount,
    beforeEnter: checkMultiStore,
  }, {
    path: '/configure/create-microsoft-account',
    name: 'create-microsoft-account',
    meta: { step: 2 },
    component: CreateMicrosoftAccount,
  }, {
    path: '/configure/select-microsoft-account',
    name: 'select-microsoft-account',
    meta: { step: 2 },
    component: SelectMicrosoftAccount,
  }, {
    path: '/configure/setup-mmc-store',
    name: 'setup-mmc-store',
    meta: { step: 3 },
    component: SetupMmcStore,
    beforeEnter: checkMmcStoreExist,
  }, {
    path: '/configure/mapping-product-attributes',
    name: 'mapping-product-attributes',
    meta: { step: 3 },
    component: MappingProductAttributes,
  }],
}, {
  path: '/',
  name: 'home',
  beforeEnter: checkStore,
}, {
  path: '/overview',
  name: 'overview-layout',
  redirect: '/overview/overview',
  component: OverviewLayout,
  children: [{
    path: '/overview/overview',
    name: 'overview',
    component: Overview,
  }, {
    path: '/overview/campaigns',
    name: 'campaigns',
    component: Campaigns,
  }, {
    path: '/overview/products',
    name: 'products',
    component: Products,
  }],
}];

const router = new VueRouter({
  routes,
});

export default router;
