const getData = (key) => {
  try {
    const data = localStorage.getItem(key);
    if (data) {
      const item = JSON.parse(data);
      if (!item.expiredAt || Date.now() < item.expiredAt) {
        return item.value;
      }
    }
    return null;
  } catch {
    localStorage.removeItem(key);
    return null;
  }
};

const setData = (key, value, expireSeconds) => {
  let expiredAt = null;
  if (expireSeconds) {
    expiredAt = Date.now() + expireSeconds * 1000;
  }
  localStorage.setItem(key, JSON.stringify({ value, expiredAt }));
};

export {
  getData,
  setData,
};
