<template>
  <svg ref="svg" height="240" width="100%">
    <line
      class="axis-baseline"
      :x1="chartPaddingX" :y1="baseline"
      :x2="width - chartPaddingX" :y2="baseline"
    />
    <g v-for="n in [1, 2, 3]" :key="`axis-${n}`">
      <line
        class="axis-dotline"
        :x1="chartPaddingX" :y1="baseline - n * axisStep"
        :x2="width - chartPaddingX" :y2="baseline - n * axisStep"
      />
      <text v-if="hasData" x="0" :y="baseline - n * axisStep + 4">
        {{ getAxisLabel(n, 0) }}
      </text>
      <text v-if="hasData" :x="width" :y="baseline - n * axisStep" text-anchor="end">
        {{ getAxisLabel(n, 1) }}
      </text>
    </g>
    <g v-if="hasData">
      <path :d="getDataLinePath(0)" class="line data1" />
      <path :d="getDataLinePath(1)" class="line data2" />
      <g v-for="(_, index) in data[0]" :key="`datapoint-${index}`" class="data-group">
        <line
          class="value-indicator"
          :x1="getPositionX(index)" :y1="chartPaddingY"
          :x2="getPositionX(index)" :y2="baseline"
        />
        <circle
          class="dot data1"
          :cx="getPositionX(index)" :cy="getPositionY(data[0][index], 0)" r="6"
        />
        <path class="dot data2" :d="getShape(data[1][index], index, 1)" />
        <g class="popup-text" style="opacity: 0.8">
          <!-- TODO: placeholder -->
          <rect :x="getPopupPositionX(index)" :y="baseline - 80" width="160" height="72" rx="4" />
          <text :x="getPopupPositionX(index) + 16" :y="baseline - 60" style="fill: white;">
            Time: {{ formatDate(getDateByIndex(index)) }}
          </text>
          <text :x="getPopupPositionX(index) + 16" :y="baseline - 40" style="fill: white;">
            {{ axis1 }}: {{ data[0][index] }}
          </text>
          <text :x="getPopupPositionX(index) + 16" :y="baseline - 20" style="fill: white;">
            {{ axis2 }}: {{ data[1][index] }}
          </text>
        </g>
      </g>
    </g>
    <text :x="chartPaddingX" y="240">{{ formatDate(startDate) }}</text>
    <text id="end-date" :x="width" y="240" text-anchor="end">{{ formatDate(endDate) }}</text>
  </svg>
</template>

<script>
import { formatDate, formatMonth } from '../../utils';
import { Granularity } from '../../models/enums/campaign-report-period';

export default {
  props: {
    data: { type: Array, default: () => [[], []] },
    axis1: { type: String, required: true },
    axis2: { type: String, required: true },
    startDate: { type: Date, default: null },
    endDate: { type: Date, default: null },
    granularity: { type: String, required: true },
  },
  data() {
    return {
      baseline: 216,
      width: 0,
      chartPaddingX: 48,
      chartPaddingY: 16,
    };
  },

  computed: {
    dataMax() {
      return this.data.map((values) => {
        const maxValue = Math.max(...values);
        const base = 10 ** Math.floor(Math.log10(maxValue));
        const highDigit = Math.ceil(maxValue / base);
        const max = 3 * Math.ceil(highDigit / 3) * base;
        return max;
      });
    },
    hasData() {
      return this.data[0].length > 0;
    },
    axisStep() {
      return (this.baseline - this.chartPaddingY) / 3;
    },
  },
  mounted() {
    // HACK: sometimes clientWidth can't get correct value. add 24px for padding.
    this.width = this.$refs.svg.clientWidth - 24;
    window.addEventListener('resize', this.onResize);
  },
  destroyed() {
    window.removeEventListener('resize', this.onResize);
  },
  methods: {
    onResize() {
      this.width = this.$refs.svg.clientWidth;
    },
    getAxisLabel(n, dataIndex) {
      const step = this.dataMax[dataIndex] / 3;
      return this.dataMax[dataIndex] - step * (3 - n);
    },
    getDataLinePath(dataIndex) {
      const str = this.data[dataIndex].reduce((pre, value, index) => {
        const x = this.getPositionX(index);
        const y = this.getPositionY(value, dataIndex);
        if (index === 0) {
          return `M${x} ${y}`;
        }
        return `${pre} L${x} ${y}`;
      }, '');

      return str;
    },
    getPositionX(index) {
      const dataSize = this.data[0].length - 1;
      if (dataSize === 0) {
        return (this.width / 2);
      }
      return (index / dataSize) * (this.width - this.chartPaddingX * 2) + this.chartPaddingX;
    },
    getPopupPositionX(index) {
      let x = this.getPositionX(index);
      if (x > this.width - 160) x -= 160; // align left if reach to right corner
      return x;
    },
    getPositionY(value, dataIndex) {
      return this.baseline
      - (value / this.dataMax[dataIndex]) * (this.baseline - this.chartPaddingY);
    },
    getShape(value, index, dataIndex) {
      const x = this.getPositionX(index);
      const y = this.getPositionY(value, dataIndex);
      const r = 7;
      return `M${x} ${y - r} L${x + r} ${y} L${x} ${y + r} L${x - r} ${y} Z`;
    },
    getDateByIndex(index) {
      const date = new Date(this.startDate);
      if (this.granularity === Granularity.DAILY) {
        date.setDate(date.getDate() + index);
        return date;
      }
      date.setMonth(date.getMonth() + index);
      return date;
    },
    formatDate(date) {
      if (this.granularity === Granularity.DAILY) {
        return formatDate(date);
      }
      return formatMonth(date);
    },
  },
};
</script>

<style scoped lang="scss">
.axis-baseline {
  stroke: #ccc;
  stroke-width: 1px;
}
.dot {
  stroke: white;
  stroke-width: 2px;
  &.data1 {
    fill: #0078d4;
  }
  &.data2 {
    fill: #022F22;
  }
}
.line {
  stroke-width: 2px;
  fill: none;
  transition: 0.3s;
  &.data1 {
    stroke: #0078d4;
  }
  &.data2 {
    stroke: #022F22;
  }
}
.axis-dotline {
  stroke-dasharray: 8, 8;
  stroke: #ccc;
  stroke-width: 1px;
}
.value-indicator {
  stroke: black;
  stroke-width: 1px;
}

.data-group {
  .value-indicator {
    stroke-dasharray: 8, 8;
    stroke: #ccc;
    stroke-width: 1px;
    opacity: 0;
  }
  .popup-text {
    display: none;
  }
  &:hover {
    .value-indicator {
      opacity: 1;
    }
    .popup-text {
      display: block;
    }
    .dot {
      transform: scale(1.5);
      transform-origin: center;
      transform-box: fill-box;
    }
  }
}
</style>
