<template>
  <div>
    <div id="attributes-mapping-form">
      <div id="mapping-item-icons">
        <div style="flex: 1">
          <img src="@/assets/image/black-ms-icon.svg">
        </div>
        <div style="flex: 1">
          <img src="@/assets/image/mapping-icon.svg">
        </div>
        <div style="flex: 2">
          <img src="@/assets/image/product-fields-icon.svg">
        </div>
      </div>
      <div id="mapping-forms">
        <div>
          {{ $t("configurations.attributesMappingPage.subtitles.microsostAttributes") }}
        </div>
        <div>
          {{ $t("configurations.attributesMappingPage.subtitles.customFields") }}
        </div>
      </div>
      <div :class="{ 'mapping-items': isScrollVisible }">
        <div v-for="(field, index) in Object.values(formLabels)" :key="field" class="form-attribute">
          <div>{{ field }}</div>
          <div>
            <b-form-select v-model="selectedRequiredFields[index]" :options="productFieldsOptions" />
          </div>
        </div>
        <div id="button-optional-attributes" @click="onToggleCollapse" @keypress="() => { }">
          <img v-if="collapsed" src="@/assets/image/up-arrow.svg">
          <img v-else src="@/assets/image/down-arrow.svg">
          <span>
            {{ $t('configurations.attributesMappingPage.optionalTitleLink') }}
          </span>
        </div>
        <div v-if="collapsed">
          <div v-for="(field, index) in Object.values(optionalFormLabels)" :key="field" class="form-attribute">
            <div>{{ field }}</div>
            <div>
              <b-form-select v-model="selectedOptionalFields[index]" :options="productFieldsOptions" />
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { mapState } from 'vuex';
import { ProductFieldsValue, NotAvailableValue } from '../../models/enums/Microsoft-product-attributes';
import { getPrestashopFieldMapping } from '../../services/bingads.service';

export default {
  name: 'AttributesMappingForm',
  props: {
    isScrollVisible: { type: Boolean, default: false },
  },
  data() {
    const RequiredAttributesDefaultValue = [
      'description',
      'price',
      'isbn',
      'mpn',
      'manufacturer',
    ];
    const OptionalAttributesDefaultValue = [
      'Not available',
      'Not available',
      'Not available',
      'Not available',
      'Not available',
      'Not available',
      'Not available',
      'Not available',
      'Not available',
      'Not available',
    ];
    const selectedRequiredFields = [];
    for (let i = 0; i < 5; i += 1) {
      selectedRequiredFields.push(RequiredAttributesDefaultValue[i]);
    }
    const selectedOptionalFields = [];
    for (let i = 0; i < 10; i += 1) {
      selectedOptionalFields.push(NotAvailableValue[0]);
    }
    const productFieldsOptions = [];
    const productFieldsText = this.$t('configurations.attributesMappingPage.productFieldsText');
    const ProductFields = Object.values(productFieldsText);
    for (let i = 0; i < ProductFields.length; i += 1) {
      productFieldsOptions.push({ value: ProductFieldsValue[i], text: ProductFields[i] });
    }
    const { attributes } = window;
    const { languageLocale } = window.i18nSettings;
    attributes.forEach((attribute) => {
      const productFieldsOption = { value: null, text: null };
      attribute.forEach((variant) => {
        if (variant.language_code === 'en-us') {
          productFieldsOption.value = variant.name;
        }
        if (variant.language_code === languageLocale) {
          productFieldsOption.text = variant.name;
        }
      });
      productFieldsOptions.push(productFieldsOption);
    });
    productFieldsOptions.push({
      value: NotAvailableValue[0],
      text: this.$t('configurations.attributesMappingPage.notAvailable'),
    });
    return {
      collapsed: false,
      selectedRequiredFields,
      selectedOptionalFields,
      productFieldsOptions,
      formLabels: this.$t('configurations.attributesMappingPage.formLabels'),
      optionalFormLabels: this.$t('configurations.attributesMappingPage.optionalFormLabels'),
      RequiredAttributesDefaultValue,
      OptionalAttributesDefaultValue,
    };
  },
  computed: {
    ...mapState({
      RequiredAttributesLocalValue:
        (state) => state.mmcStore.RequiredAttributesLocalValue,
      OptionalAttributesLocalValue:
        (state) => state.mmcStore.OptionalAttributesLocalValue,
    }),
    finishDisable() {
      return (this.selectedRequiredFields[0] === NotAvailableValue[0])
        || (this.selectedRequiredFields[1] === NotAvailableValue[0]);
    },
  },
  watch: {
    finishDisable: {
      handler(newValue) {
        this.$store.commit('mmcStore/SAVE_FINISH_DISABLE', newValue);
      },
      immediate: true,
    },
  },
  mounted() {
    this.getFieldMapping();
  },
  methods: {
    onToggleCollapse() {
      this.collapsed = !this.collapsed;
    },
    async getFieldMapping() {
      if (this.RequiredAttributesLocalValue[0] !== NotAvailableValue[0]) {
        for (let i = 0; i < 5; i += 1) {
          this.selectedRequiredFields[i] = this.RequiredAttributesLocalValue[i];
        }
        for (let i = 0; i < 10; i += 1) {
          this.selectedOptionalFields[i] = this.OptionalAttributesLocalValue[i];
        }
        this.$forceUpdate();
      } else {
        try {
          const data = await getPrestashopFieldMapping();
          const values = Object.values(data);
          if (values[0] !== null) {
            for (let i = 0; i < values.length; i += 1) {
              if (values[i] !== null) {
                if (i < 5) {
                  this.selectedRequiredFields[i] = values[i];
                } else if (i < 15) {
                  this.selectedOptionalFields[i - 5] = values[i];
                }
              } else if (values[i] === null) {
                if (i < 5) {
                  // eslint-disable-next-line prefer-destructuring
                  this.selectedRequiredFields[i] = NotAvailableValue[0];
                } else if (i < 15) {
                  // eslint-disable-next-line prefer-destructuring
                  this.selectedOptionalFields[i - 5] = NotAvailableValue[0];
                }
              }
            }
          }
        } finally {
          this.$forceUpdate();
        }
      }
    },
  },
};
</script>

