<template>
  <b-button :variant="variant" :disabled="disabled || loading" @click="onClick">
    <div class="fluent-btn-container">
      <span class="fluent-btn-spinner"><b-spinner v-show="loading" small /></span>
      <span class="fluent-btn-text" :class="{loading: loading}">
        <slot />
      </span>
    </div>
  </b-button>
</template>

<script>
export default {
  name: 'FluentButton',
  props: {
    variant: { type: String, required: true },
    disabled: { type: Boolean, default: false },
    loading: { type: Boolean, default: false },
  },
  methods: {
    onClick(event) {
      this.$emit('click', event);
    },
  },
};
</script>

<style lang="scss" scoped>

.fluent-btn-container {
  position: relative;
}
.fluent-btn-text {
  width: 100%;
  height: 100%;
}
.fluent-btn-spinner {
  position: absolute;
  left: calc(50% - 8px);
}
.fluent-btn-text.loading {
  opacity: 0.01;
}
</style>
