<template>
  <div>
    <p style="font-weight: 600;font-size: 22px;">
      {{ $t("configurations.syncProductsToMicrosoftPage.title") }}
    </p>
    <p style="font-weight: 400;font-size: 14px;">
      {{ $t("configurations.syncProductsToMicrosoftPage.descriptions.title") }}
    </p>
    <div>
    <span
      style="font-weight: 600;
      font-size: 14px;
             margin-top: 32px;
             margin-bottom: 8px"
    >
      {{ $t("configurations.syncProductsToMicrosoftPage.subtitles.storeName") }}
    </span>
    <img v-if="storeNameToolTipVisible" id="storeNameTip"
      src="@/assets/image/icon-question-outline.svg">
    <b-tooltip
      target="storeNameTip" placement="right">
      <p>
        {{ $t("configurations.syncProductsToMicrosoftPage.tooltip.title") }}
      </p>
      <p>
        {{ $t("configurations.syncProductsToMicrosoftPage.tooltip.content",
      { storename: mmcStoreName, domain: storeUrl }) }}
      </p>
    </b-tooltip>
    </div>
    <b-form-group
      id="input-group-1"
      label-for="input-1"
      style="width: 50%; margin-top: 16px"
      :invalid-feedback="nameFeedback"
      :state="nameState"
    >
      <b-form-input
        v-model="mmcStoreName"
        :placeholder="$t('configurations.syncProductsToMicrosoftPage.placeholders.storeName')"
        :disabled="mmcApiInfo !== null"
        :state="nameState"
      />
    </b-form-group>
    <p
      style="font-weight: 600;
             font-size: 14px;
             margin-top: 32px;
             margin-bottom: 8px"
    >
      {{ $t("configurations.syncProductsToMicrosoftPage.subtitles.storeLanguage") }}
    </p>
    <p
      style="font-weight: 400;
    font-size: 14px;"
    >
      {{ language }}
    </p>
    <p
      style="font-weight: 600;
            font-size: 14px;
            margin-top: 32px;
            margin-bottom: 8px;"
    >
      {{ $t("configurations.syncProductsToMicrosoftPage.subtitles.targetMarket") }}
    </p>
    <p
      style="font-weight: 400;
             font-size: 14px;
             margin-top: 8px;"
    >
      {{ $t("configurations.syncProductsToMicrosoftPage.descriptions.targetMarket") }}
    </p>
    <div style="width: 50%; margin-top: 8px">
      <b-form-select v-model="selected" :options="availiableMarketsOptions" />
    </div>
    <p v-if="!isAvailable" style="color: #A80000;">
      {{ $t("configurations.syncProductsToMicrosoftPage.warnings.invaildMarket"
            , {market: market}) }}
      <a :href="localizationUrl">
        {{ $t('configurations.syncProductsToMicrosoftPage.warnings.localization') }}
      </a>
      {{ $t("configurations.syncProductsToMicrosoftPage.warnings.page") }}
    </p>
    <!-- <a href=""></a> -->
    <div v-if="shippingDisplay">
      <p style="margin-top:16px">
        {{ $t("configurations.syncProductsToMicrosoftPage.descriptions.hints") }}
        <a target="_blank" href="https://help.ads.microsoft.com/#apex/ads/en/51084/1/#exp19">
          {{ $t("general.actions.learnMore") }}
        </a>
      </p>
      <div style="display: flex; flex-direction: row;">
        <p
          style="font-weight: 600;
            font-size: 14px;
            margin-top: 32px;
            margin-bottom: 8px;"
        >
          {{ $t("configurations.syncProductsToMicrosoftPage.subtitles.freeShipping") }}
        </p>
        <div
          style="display: flex; flex-direction: row; font-size: 14px;
            margin-top: 16px;
            margin-bottom: 8px;
            margin-left: 160px;"
        >
          <f-switch
            v-model="freeShipping" label-on="On" label-off="Off" label=""
          />
        </div>
      </div>
      <div v-if="shippingRateDisplay">
        <p
          style="font-weight: 600;
            font-size: 14px;
            margin-top: 32px;
            margin-bottom: 8px;"
        >
          {{ $t("configurations.syncProductsToMicrosoftPage.subtitles.shippintRate") }}
        </p>
        <div style="display: flex; flex-direction: row; width: 25%">
          <b-form-input v-model="shippingRate" />
          <p style="margin-left:8px; font-weight: 500;">
            EUR
          </p>
        </div>
      </div>
    </div>
    <p
      style="font-weight: 600; font-size: 14px;
             margin-top: 32px;
             margin-bottom: 8px"
    >
      {{ $t("configurations.syncProductsToMicrosoftPage.subtitles.catalogSync") }}
    </p>
    <p>
      {{ $t("configurations.syncProductsToMicrosoftPage.descriptions.catalogSync") }}
    </p>
    <div style="margin-top: 44px; padding-bottom: 200px;">
      <f-button
        variant="primary"
        :disabled="continueDisabled"
        style="margin-right: 12px"
        :loading="continueLoading"
        @click="onContinue"
      >
        {{ $t('general.buttons.continue') }}
      </f-button>
      <f-button variant="outline-secondary" :loading="backLoading" @click="onBack">
        {{ $t('general.buttons.back') }}
      </f-button>
    </div>
    <f-modal
      :visible="modalVisible"
      :title="$t('overviewPage.account.disconnectModal.title')"
      :modal-style="{ width: '680px' }"
      :primary-button-name="$t('overviewPage.account.disconnectModal.cancel')"
      :secondary-button-name="$t('overviewPage.account.disconnectModal.disconnect')"
      :secondary-loading="disconnectLoading"
      @secondaryAction="disconnect"
      @primaryAciton="onHideModal"
      @close="onHideModal"
    >
      <div>
        {{ $t('overviewPage.account.disconnectModal.content') }}
      </div>
    </f-modal>
    <f-modal
      :visible="existingStoreModalVisible"
      :title="$t('configurations.syncProductsToMicrosoftPage.modals.title',
        { storename: mmcStoreName })"
      :modal-style="{ width: '680px' }"
      :primary-button-name="$t('general.buttons.ok')"
      @primaryAciton="onHideExistingStoreModal"
      @secondaryAction="onHideExistingStoreModal"
      @close="onHideExistingStoreModal"
    >
      <div>
        {{ $t('configurations.syncProductsToMicrosoftPage.modals.content') }}
      </div>
    </f-modal>
  </div>
</template>

<script>
import { mapMutations, mapState } from 'vuex';
import {
  isAvailableMarket, getAccountStatus, disconnect, validateCreateStoreParams,
} from '../../services/bingads.service';
import {
  hasStoreNameMustContainedCharacters,
  hasSuspiciousCharacters,
  hasStoreNameDisallowedCharacters,
} from '../../utils';

export default {
  name: 'MmcStoreSection',
  data() {
    const shopUrl = window.contextPsAccounts.currentShop.url;
    const storeUrl = window.shopUrlForMicrosoft;
    const { _token } = window;
    const localizationUrl = `${shopUrl.substring(0, shopUrl.indexOf('?controller'))
    }/improve/international/localization/?_token${_token}`;
    const currencyCode = window.currency;
    const language = window.language.name;
    const languageCode = window.language.iso_code;
    const country = window.defaultCountry;
    const countryCode = window.defaultCountryCode;
    const marketCode = `${languageCode}-${countryCode}`;
    const market = `${language}-${country}`;
    const availiableMarketsOptions = [];
    const selected = marketCode;
    const isAvailable = true;
    const mmcStoreName = null;
    const mmcStoreNameApi = null;
    const freeShipping = true;
    const shippingRate = null;
    return {
      localizationUrl,
      currencyCode,
      language,
      languageCode,
      country,
      countryCode,
      selected,
      marketCode,
      market,
      availiableMarketsOptions,
      isAvailable,
      mmcStoreName,
      freeShipping,
      shippingRate,
      mmcStoreNameApi,
      backLoading: false,
      continueLoading: false,
      modalVisible: false,
      disconnectLoading: false,
      existingStoreModalVisible: false,
      storeNameToolTipVisible: false,
      storeUrl,
    };
  },
  computed: {
    ...mapState({
      storeName: (state) => state.mmcStore.storeName,
      freeShippingState: (state) => state.mmcStore.freeShipping,
      shippingRateState: (state) => state.mmcStore.shippingRate,
      mmcApiInfo: (state) => state.mmcStore.mmcApiInfo,
    }),
    continueDisabled() {
      return this.mmcStoreName === undefined
      || this.mmcStoreName === null
      || this.mmcStoreName === ''
      || !this.isAvailable
      || !this.nameState;
    },
    shippingDisplay() {
      if (this.marketCode === 'de-AT' || this.marketCode === 'de-DE') {
        return true;
      }
      return false;
    },
    shippingRateDisplay() {
      return this.freeShipping === false;
    },
    nameFeedback() {
      const maxLength = 70;
      if (this.mmcStoreName?.length > maxLength) {
        return this.$t('configurations.syncProductsToMicrosoftPage.storeNameError.invalidLength');
      }
      if (!hasStoreNameMustContainedCharacters(this.mmcStoreName)) {
        return this.$t('configurations.syncProductsToMicrosoftPage.storeNameError.notContainedCharacters');
      }
      if (hasSuspiciousCharacters(this.mmcStoreName)) {
        return this.$t('configurations.syncProductsToMicrosoftPage.storeNameError.hasSuspiciousCharacters');
      }
      if (hasStoreNameDisallowedCharacters(this.mmcStoreName)) {
        return this.$t('configurations.syncProductsToMicrosoftPage.storeNameError.hasStoreNameDisallowedCharacters');
      }
      return this.$t('configurations.syncProductsToMicrosoftPage.storeNameError.hasSuspiciousCharacters');
    },
    nameState() {
      if (this.mmcStoreName === null) {
        return true;
      }
      const maxLength = 70;
      if (this.mmcStoreName?.length > maxLength) {
        return false;
      }
      if (!hasStoreNameMustContainedCharacters(this.mmcStoreName)) {
        return false;
      }
      if (hasSuspiciousCharacters(this.mmcStoreName)) {
        return false;
      }
      if (hasStoreNameDisallowedCharacters(this.mmcStoreName)) {
        return false;
      }
      return true;
    },
  },
  async mounted() {
    const accountInfo = await getAccountStatus();
    const email = accountInfo.signed_up_email;
    this.SAVE_ACCOUNT_EMAIL(email);
    if (this.mmcApiInfo !== null) {
      this.mmcStoreName = this.mmcApiInfo.StoreName;
      this.existingStoreModalVisible = true;
      this.storeNameToolTipVisible = (this.mmcApiInfo.StoreName
        !== window.contextPsAccounts.currentShop.name);
    } else if (hasStoreNameMustContainedCharacters(window.contextPsAccounts.currentShop.name)
          && !hasSuspiciousCharacters(window.contextPsAccounts.currentShop.name)
          && !hasStoreNameDisallowedCharacters(window.contextPsAccounts.currentShop.name)) {
      this.mmcStoreName = window.contextPsAccounts.currentShop.name;
    }
    this.isAvailable = await isAvailableMarket(this.marketCode);
    if (this.isAvailable) {
      this.availiableMarketsOptions = [{ value: this.marketCode, text: this.country }];
      this.freeShipping = this.freeShippingState;
      this.shippingRate = this.shippingRateState;
      if ((this.marketCode === 'de-AT' || this.marketCode === 'de-DE') && this.shippingRate === null) {
        this.shippingRate = 0;
      }
    }
  },
  methods: {
    ...mapMutations('mmcStore', ['SAVE_STORE_NAME', 'SAVE_MARKET_CODE', 'SAVE_FREE_SHIPPING', 'SAVE_SHIPPING_RATE']),
    ...mapMutations('accounts', ['SAVE_ACCOUNT_EMAIL']),
    async onContinue() {
      try {
        this.continueLoading = true;
        if (this.mmcApiInfo === null) {
          const storeParams = {
            store_name: this.mmcStoreName,
            store_url: window.shopUrlForMicrosoft,
            technical_contact_email: window.contextPsAccounts.user.email,
          };
          await validateCreateStoreParams(storeParams);
        }
        if (this.freeShipping) {
          this.shippingRate = 0;
        }
        if (this.shippingRate === 0) {
          this.freeShipping = true;
        }
        this.SAVE_STORE_NAME(this.mmcStoreName);
        this.SAVE_MARKET_CODE(this.marketCode);
        this.SAVE_FREE_SHIPPING(this.freeShipping);
        this.SAVE_SHIPPING_RATE(this.shippingRate);
        this.$router.push({ name: 'mapping-product-attributes' });
      } catch {
        this.continueLoading = false;
      }
    },
    async onBack() {
      this.modalVisible = true;
    },
    onHideModal() {
      this.modalVisible = false;
    },
    onHideExistingStoreModal() {
      this.existingStoreModalVisible = false;
    },
    async disconnect() {
      try {
        this.disconnectLoading = true;
        await disconnect();
        const redirectUrl = window.contextPsAccounts.currentShop.url;
        window.location.href = redirectUrl;
      } catch {
        this.disconnectLoading = false;
      }
    },
  },
};
</script>

