<template>
  <skeletion-card v-if="isLoading" :title="$t('overviewPage.titles.microsoftAdsAccount')" />
  <section-card v-else :title="$t('overviewPage.titles.microsoftAdsAccount')">
    <template #body>
      <div style="display: flex; align-items: center;">
        <span class="section-title">{{ $t('overviewPage.account.titles.accountName') }}</span>
        <span class="section-value">{{ accountName }}</span>
      </div>
      <div style="display: flex; align-items: center;">
        <span class="section-title">{{ $t('overviewPage.account.titles.accountId') }}</span>
        <span class="section-value">{{ accountId }}</span>
      </div>
      <div style="display: flex; align-items: center;">
        <span class="section-title">{{ $t('overviewPage.account.titles.customerId') }}</span>
        <span class="section-value">{{ customerId }}</span>
      </div>
    </template>
    <template #buttons>
      <a
        v-if="accountStatus === AccountStatusType.CONNECTED"
        variant="link" style="cursor:pointer;"
        @click="openModal" @keypress="openModal"
      >
        {{ $t('overviewPage.account.buttons.disconnect') }}
      </a>
      <div
        v-if="accountStatus === AccountStatusType.SIGNED_UP_NOT_CONNECTED
          || accountStatus === AccountStatusType.SIGN_UP_INVITATION_SENT_NOT_ACCEPTED"
      >
        <f-button
          variant="primary"
          :loading="connectLoading"
          style="margin-right: 12px"
          @click="onConnect"
        >
          {{ $t('overviewPage.account.buttons.connect') }}
        </f-button>
        <f-button
          v-if="accountStatus === AccountStatusType.SIGN_UP_INVITATION_SENT_NOT_ACCEPTED"
          variant="outline-secondary" :loading="resendLoading"
          @click="onResendEmail"
        >
          {{ $t('overviewPage.account.buttons.resendEmail') }}
        </f-button>
      </div>
      <f-modal
        :visible="modalVisible"
        :title="$t('overviewPage.account.disconnectModal.title')"
        :modal-style="{ width: '680px' }"
        :primary-button-name="$t('overviewPage.account.disconnectModal.cancel')"
        :secondary-button-name="$t('overviewPage.account.disconnectModal.disconnect')"
        :secondary-loading="disconnectLoading"
        @secondaryAction="disconnect"
        @primaryAciton="onHideModal"
        @close="onHideModal"
      >
        <div>
          {{ $t('overviewPage.account.disconnectModal.content') }}
        </div>
      </f-modal>
    </template>
  </section-card>
</template>

<script>
import SectionCard from './SectionCard.vue';
import SkeletionCard from './SkeletionCard.vue';
import {
  getAccountStatus, resendEmail, signInMSAccount, disconnect,
} from '../../services/bingads.service';
import AccountStatus from '../../models/enums/account-status';

export default {
  name: 'AccountSectionCard',
  components: {
    SectionCard,
    SkeletionCard,
  },
  data() {
    return {
      accountName: '',
      accountId: '',
      customerId: '',
      accountStatus: '',
      AccountStatusType: AccountStatus,
      connectLoading: false,
      resendLoading: false,
      isLoading: true,
      modalVisible: false,
      disconnectLoading: false,
    };
  },
  async mounted() {
    this.init();
  },
  methods: {
    async init() {
      const accountInfo = await getAccountStatus();
      this.accountStatus = accountInfo.bingads_account_status;
      this.accountName = accountInfo.bingads_account.AccountName;
      this.accountId = accountInfo.bingads_account.AccountId;
      this.customerId = accountInfo.bingads_account.CustomerId;
      this.isLoading = false;
    },
    async openModal() {
      this.modalVisible = true;
    },
    async onConnect() {
      this.connectLoading = true;
      try {
        const url = window.location.href;
        const connectUrl = url.replace('/overview/overview', '/configure/connect-microsoft-account');
        const backUrl = encodeURIComponent(connectUrl);
        const redirectUrl = await signInMSAccount(backUrl);
        window.top.location.href = redirectUrl;
      } finally {
        setTimeout(() => {
          this.connectLoading = false;
        }, 3000);
      }
    },
    async onResendEmail() {
      this.resendLoading = true;
      try {
        // eslint-disable-next-line camelcase
        const { signup_invitation_sent_limited } = await resendEmail();
        let content = this.$t('campaignPage.banner.confirmEmail.resendSucceed');
        let variant = 'success';
        let title = this.$t('general.errorTitle.succeed');
        // eslint-disable-next-line camelcase
        if (signup_invitation_sent_limited) {
          content = this.$t('general.errorMap.SignUpInvitationSentLimited');
          variant = 'danger';
          title = this.$t('general.errorTitle.error');
        }
        window.$vue.$bvToast.toast(content, {
          toaster: 'b-toaster-bottom-center',
          noCloseButton: true,
          title,
          toastClass: 'fluent-toast resendEmail',
          solid: true,
          static: true,
          variant,
        });
      } finally {
        this.resendLoading = false;
      }
    },
    onHideModal() {
      this.modalVisible = false;
    },
    async disconnect() {
      try {
        this.disconnectLoading = true;
        await disconnect();
        const redirectUrl = window.contextPsAccounts.currentShop.url;
        window.location.href = redirectUrl;
      } catch {
        this.disconnectLoading = false;
      }
    },
  },
};
</script>

<style scoped lang="scss">
.section-title {
  font-weight: 600;
  width: 132px;
  margin-right: 8px;
  display: inline-block;
}

.section-value{
  display: inline-block;
}

</style>
