import { getCampaignInfo, getCouponDuration, getCouponClass } from '../../../services/bingads.service';

const actions = {
  async getCampaignInfo({
    commit,
  }) {
    const campaignInfo = await getCampaignInfo();
    commit('SAVE_CAMPAIGN_INFO', campaignInfo);
  },
  async getCouponDuration({
    commit,
  }) {
    // eslint-disable-next-line camelcase
    const { duration_in_days } = await getCouponDuration();
    commit('SAVE_COUPON_DURATION', duration_in_days);
  },
  async getCouponClass({
    commit,
  }) {
    const country = window.defaultCountryCode;
    // eslint-disable-next-line camelcase
    const couponclass = await getCouponClass(country);
    // eslint-disable-next-line camelcase
    commit('SAVE_COUPON_CLASS', couponclass);
  },
};

export default actions;
