<template>
  <div id="store-requirements">
    <div id="header-section">
      <div class="ms-ps-title">
        {{ $t("configurations.storeRequirementsPage.title") }}
      </div>
      <div class="ms-ps-subtitle">
        {{ $t("configurations.storeRequirementsPage.subtitle") }}
        <a target="_blank" href="https://help.ads.microsoft.com/#apex/ads/en/52023">
          {{ $t("general.actions.learnMore") }}
        </a>
      </div>
    </div>
    <div id="review-policy">
      <a target="_blank" :href="linkUrl">
        {{ $t("configurations.storeRequirementsPage.reviewPolicy") }}
      </a>
    </div>
    <div id="check-list">
      <b-form-checkbox v-model="checkboxStatus[0]" :value="true" :unchecked-value="false">
        {{ $t('configurations.storeRequirementsPage.checklists.content1') }}
      </b-form-checkbox>
      <b-form-checkbox v-model="checkboxStatus[1]" :value="true" :unchecked-value="false">
        {{ $t('configurations.storeRequirementsPage.checklists.content2') }}
      </b-form-checkbox>
      <b-form-checkbox v-model="checkboxStatus[2]" :value="true" :unchecked-value="false">
        {{ $t('configurations.storeRequirementsPage.checklists.content3') }}
      </b-form-checkbox>
      <b-form-checkbox v-model="checkboxStatus[3]" :value="true" :unchecked-value="false">
        {{ $t('configurations.storeRequirementsPage.checklists.content4') }}
        <a target="_blank" href="https://about.ads.microsoft.com/en-us/policies/home">
          {{ $t('configurations.storeRequirementsPage.checklists.content4Link') }}
        </a>
      </b-form-checkbox>
    </div>
    <div style="margin-top: 44px; padding-bottom: 200px;">
      <f-button
        variant="primary"
        :loading="loading"
        style="margin-right: 12px"
        :disabled="isRequirementsCompleted"
        @click="onClickContinue"
      >
        {{ $t('general.buttons.continue') }}
      </f-button>
      <f-button variant="outline-secondary" @click="onClickBack">
        {{ $t('general.buttons.back') }}
      </f-button>
    </div>
  </div>
</template>

<script>
import { confirmCheckListItems, install } from '../../services/bingads.service';
import { savePublicKey } from '../../services/prestashop.service';

export default {
  data() {
    const shopUrl = window.contextPsAccounts.currentShop.url;
    const { _token } = window;
    const linkUrl = `${shopUrl.substring(0, shopUrl.indexOf('?controller'))
    }/improve/design/cms-pages/?_token${_token}`;
    return {
      checkboxStatus: [false, false, false, false],
      loading: false,
      linkUrl,
    };
  },
  computed: {
    isRequirementsCompleted() {
      return this.checkboxStatus.some((x) => x === false);
    },
  },
  async mounted() {
    try {
      const installInfo = {
        store_domain: window.contextPsAccounts.currentShop.uuid,
        shop_domain: window.contextPsAccounts.currentShop.domain,
        store_url: window.shopUrlForMicrosoft,
        shop_id: window.contextPsAccounts.currentShop.id,
      };
      const publicKey = await install(installInfo);
      const saveKey = {
        action: 'savePublicKey',
        publicKey,
      };
      await savePublicKey(saveKey);
    } catch {
      this.loading = false;
    }
  },
  methods: {
    onClickBack() {
      this.$router.push({ name: 'prestashop-setup' });
    },

    async onClickContinue() {
      this.loading = true;
      try {
        await confirmCheckListItems();
        this.$router.push({ name: 'connect-microsoft-account' });
      } finally {
        this.loading = false;
      }
    },
  },
};
</script>

<style lang="scss" scoped>
#review-policy {
  margin: 18px 0;
}

#check-list>div {
  margin-top: 8px;
}

#button-group {
  margin-top: 44px;
}
</style>
