<template>
  <div>
    <f-alert :show="isFraudStore" variant="danger" style="margin-bottom: 32px">
      <span>{{ $t('overviewPage.banner.descriptionPrefix') }}</span>
      <a
        target="_blank" href="https://about.ads.microsoft.com/en-us/microsoft-advertising-support"
      >{{ $t('overviewPage.banner.link') }}
      </a>
    </f-alert>
    <div id="card-list">
      <products-section-card />
      <campaigns-section-card />
      <account-section-card />
    </div>
    <feedback-footer />
  </div>
</template>

<script>

import ProductsSectionCard from '../../components/overview/ProductsSectionCard.vue';
import CampaignsSectionCard from '../../components/overview/CampaignsSectionCard.vue';
import AccountSectionCard from '../../components/overview/AccountSectionCard.vue';
import FeedbackFooter from '../../components/overview/FeedbackFooter.vue';
import { checkStoreExisting } from '../../services/bingads.service';
import MmcStoreStatus from '../../models/enums/mmc-store-status';

export default {
  components: {
    ProductsSectionCard,
    CampaignsSectionCard,
    AccountSectionCard,
    FeedbackFooter,
  },

  data() {
    return {
      hasCampaign: false,
      isFraudStore: false,
    };
  },
  mounted() {
    this.getMmcStoreInfo();
  },
  methods: {
    async getMmcStoreInfo() {
      const mmcStoreInfo = await checkStoreExisting();
      this.isFraudStore = !(mmcStoreInfo?.mmc_api_store?.storeStatus?.status
        === MmcStoreStatus.APPROVE);
    },
  },
};
</script>

<style scoped lang="scss">
