<template>
  <section-card :title="$t('overviewPage.titles.campaigns')">
    <template #body>
      <div class="title">
        {{ $t('overviewPage.campaigns.title') }}
      </div>
      <div class="subtitle">
        {{ $t('overviewPage.campaigns.description') }}
        <a target="_blank" href="https://help.ads.microsoft.com/#apex/ads/en/60058/1">
          {{ $t('general.actions.learnMore') }}
        </a>
      </div>
      <CouponNotRedeemedBannerVue />
    </template>
    <template #buttons>
      <b-button variant="primary" @click="onClickGetStarted">
        {{ $t('general.buttons.create') }}
      </b-button>
    </template>
  </section-card>
</template>

<script>
import { mapActions, mapState } from 'vuex';
import SectionCard from './SectionCard.vue';
import CouponNotRedeemedBannerVue from '../campaign/CouponNotRedeemedBanner.vue';

export default {
  name: 'NoCampaignsSectionCard',
  components: {
    SectionCard,
    CouponNotRedeemedBannerVue,
  },
  data() {
    return {
      isBannerShow: false,
    };
  },
  computed: {
    ...mapState({
      couponDuration: (state) => state.market.couponDuration,
      couponValue: (state) => state.market.couponValue,
      upFrontSpending: (state) => state.market.upFrontSpending,
    }),
  },
  mounted() {
    this.bannerShow();
  },
  methods: {
    ...mapActions('market', ['getCouponDuration', 'getCouponClass']),
    onClickGetStarted() {
      this.$router.push({ name: 'campaigns' });
    },
    async bannerShow() {
      await this.getCouponDuration();
      if (this.couponDuration >= 0 && this.couponDuration <= 30) {
        await this.getCouponClass();
        this.isBannerShow = true;
      }
    },
  },
};
</script>

<style scoped lang="scss">
.title {
  font-weight: 600;
}
.subtitle {
  margin-top: 16px;
}
</style>
