<template>
  <div id="overview-menu-tab-bar">
    <div
      v-for="item in items" :key="item"
      :class="{active: $route.name === item}"
      @click="onClickNaviItem(item)"
      @keydown="() => {}"
    >
      {{ $t(`general.navigation.${item}`) }}
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      items: ['overview', 'products', 'campaigns'],
    };
  },
  methods: {
    onClickNaviItem(name) {
      this.$router.push({ name });
    },
  },
};
</script>

