<template>
  <div>
    <div id="products-card-list">
      <b-card class="product-card">
        <div>
          <img class="product-card-icon" src="@/assets/image/icon-status-succeed.svg">
          <span>{{ $t('productsPage.products.listed') }}</span>
        </div>
        <div class="product-card-value">
          {{ listed }}
        </div>
      </b-card>
      <b-card class="product-card">
        <div>
          <img class="product-card-icon" src="@/assets/image/icon-status-info.svg">
          <span>{{ $t('productsPage.products.pending') }}</span>
        </div>
        <div class="product-card-value">
          {{ pending }}
        </div>
      </b-card>
      <b-card class="product-card">
        <div>
          <img class="product-card-icon" src="@/assets/image/icon-status-warning.svg">
          <span>{{ $t('productsPage.products.issued') }}</span>
        </div>
        <div class="product-card-value">
          {{ issued }}
        </div>
      </b-card>
    </div>
    <p style="margin: 8px; color: #6D7175">
      {{ $t('overviewPage.products.processReminder') }}
    </p>
    <div id="products-issue">
      <span>
        <b-button variant="link" style="margin: 48px 0 24px 0" @click="onShowModal">
          <img class="edit-icon" src="@/assets/image/icon-edit.svg">
          <span>{{ $t('productsPage.buttons.edit') }}</span>
        </b-button>
        <b-button variant="link" style="margin: 48px 0 24px 0" @click="onVisitMmc">
          <span>{{ $t('productsPage.buttons.visitMmc') }}</span>
        </b-button>
      </span>
      <b-table :items="items" :fields="productIssuesFields" />
    </div>

    <f-modal
      :title="$t('productsPage.modal.title')" :visible="modalVisible"
      :modal-style="{width: '944px'}" :button-disabled="finishDisable"
      :primary-loading="saveLoading" @secondaryAction="onCloseModal"
      @primaryAciton="onSave" @close="onCloseModal"
      :primary-button-name="$t('general.buttons.save')"
      :secondary-button-name="$t('general.buttons.cancel')"
    >
      <div style="margin-bottom: 24px">
        <span>{{ $t('productsPage.modal.description') }} </span>
        <a target="_blank" href="https://help.ads.microsoft.com/#apex/ads/en/51084">
          {{ $t('productsPage.modal.action') }}
        </a>
      </div>
      <attributes-mapping-form ref="AttributesMappingForm" :is-scroll-visible="true" />
    </f-modal>
  </div>
</template>

<script>
import { mapState } from 'vuex';
import { RequiredAttributes, OptionalAttributes, NotAvailableValue } from '../../models/enums/Microsoft-product-attributes';
import {
  upsertPrestashopFieldMapping, getMmcOfferStatus, getProductIssues, checkStoreExisting,
} from '../../services/bingads.service';
import AttributesMappingForm from '../../components/overview/AttributesMappingForm.vue';
import CountryCodesAttributes from '../../models/enums/country-code';
import config from '../../config';
import MmcStoreStatus from '../../models/enums/mmc-store-status';

export default {
  components: { AttributesMappingForm },
  data() {
    return {
      items: [],
      modalVisible: false,
      RequiredAttributes,
      OptionalAttributes,
      saveLoading: false,
      listed: '/',
      pending: '/',
      issued: '/',
      aid: null,
      cid: null,
      uid: null,
      isFraudStore: false,
      productIssuesFields: [
        { key: 'productIssue', label: this.$t('productsPage.table.titles.productIssue') },
        { key: 'affectedCountries', label: this.$t('productsPage.table.titles.affectedCountries') },
      ],
    };
  },
  computed: {
    ...mapState({
      shippingRate: (state) => state.mmcStore.shippingRate,
      finishDisable: (state) => state.mmcStore.finishDisable,
    }),
    productIssueUrl() {
      return `${config.bingadsProductIssueUrl}&aid=${this.aid}&cid=${this.cid}&storeId=${this.uid}`;
    },
  },
  mounted() {
    this.getMmcInfo();
  },
  methods: {
    onShowModal() {
      this.modalVisible = true;
    },
    onCloseModal() {
      this.modalVisible = false;
    },
    onVisitMmc() {
      window.open(this.productIssueUrl);
    },
    async onSave() {
      this.saveLoading = true;
      const mmcStoreInfo = {};
      mmcStoreInfo.shipping_rate = this.shippingRate;
      const fieldMapping = {};
      const { selectedRequiredFields } = this.$refs.AttributesMappingForm;
      const { selectedOptionalFields } = this.$refs.AttributesMappingForm;
      RequiredAttributes.forEach((requiredAttribute, index) => {
        if (selectedRequiredFields[index] !== NotAvailableValue[0]) {
          fieldMapping[requiredAttribute] = selectedRequiredFields[index];
        }
      });
      OptionalAttributes.forEach((optionalattribute, index) => {
        if (selectedOptionalFields[index] !== NotAvailableValue[0]) {
          fieldMapping[optionalattribute] = selectedOptionalFields[index];
        }
      });
      mmcStoreInfo.field_mapping = fieldMapping;
      mmcStoreInfo.store_domain = window.contextPsAccounts.currentShop.uuid;
      try {
        await upsertPrestashopFieldMapping(mmcStoreInfo);
        this.modalVisible = false;
      } finally {
        this.saveLoading = false;
      }
    },
    async getMmcOfferStatus() {
      const offerStatus = await getMmcOfferStatus();
      this.listed = offerStatus.approved;
      this.pending = offerStatus.pending;
      this.issued = offerStatus.rejected;
    },
    async getProductIssues() {
      const productIssues = await getProductIssues(window.i18nSettings.isoCode);
      const issues = productIssues.value?.map((issue) => {
        const countries = issue.AffectedCountries.map((code) => CountryCodesAttributes[code]);
        const affectedCountries = countries.join(', ');
        return { productIssue: issue.IssueMessage, affectedCountries };
      });
      if (issues === undefined || issues === null || issues.length === 0) {
        const slashPlaceHolder = [{ productIssue: '/', affectedCountries: '/' }];
        this.items = slashPlaceHolder;
      } else {
        this.items = issues;
      }
    },
    async getMmcInfo() {
      const storeInfo = await checkStoreExisting();
      this.aid = storeInfo?.mmc_api_store?.AccountId;
      this.cid = storeInfo?.mmc_api_store?.CustomerId;
      this.uid = storeInfo?.mmc_api_store?.ProviderId;
      this.isFraudStore = !(storeInfo?.mmc_api_store?.storeStatus?.status
        === MmcStoreStatus.APPROVE);
      if (this.isFraudStore === true) {
        return;
      }
      this.getMmcOfferStatus();
      this.getProductIssues();
    },
  },
};
</script>

