const getPsAccountToken = () => window.psAccountToken;

const formatDate = (date) => `${date.getFullYear()}-${date.getMonth() + 1}-${date.getDate()}`;
const formatMonth = (date) => `${date.getFullYear()}-${date.getMonth() + 1}`;

const hasStoreNameMustContainedCharacters = (source) => {
  // Japanese Store names can possibly have no english alphabets
  const m = /[a-zA-Z0-9\u2E80-\u2FD5\u3000-\u3096\u30A0-\u30FF\u3190-\u319F\u3400-\u4DBF\u4E00-\u9FCC\uF900-\uFAAD\uFF00-\uFFEF]/;
  return m.test(source);
};
const hasSuspiciousCharacters = (source) => {
  const suspUrl = /^[a-zA-Z]+:\/\//;
  const suspTag = /<.*?>/;
  return (suspUrl.test(source) || suspTag.test(source));
};

const hasStoreNameDisallowedCharacters = (source) => {
  // International support: new pattern matcch \u00C0-\u017F
  // added into previous string to support accent chars
  const dis = /[^ \t\u2018\u2019\u201c\u201d\u00C0-\u017F~‘’｀´`\u2E80-\u2FD5\u3000-\u3096\u30A0-\u30FF\u3190-\u319F\u3400-\u4DBF\u4E00-\u9FCC\uF900-\uFAAD\uFF00-\uFFEFa-zA-Z0-9≪≫!@#$%^&*()_+‐＋\-={}…±×÷≠∞♯[\]:;“”〜"',.?/|\\]/;
  return dis.test(source);
};

export {
  getPsAccountToken,
  formatDate,
  formatMonth,
  hasStoreNameMustContainedCharacters,
  hasSuspiciousCharacters,
  hasStoreNameDisallowedCharacters,
};
