import Vue from 'vue';
import VueI18n from 'vue-i18n';
import { messages } from './translations';

Vue.use(VueI18n);

const { i18nSettings } = window;
const locale = i18nSettings?.isoCode || 'en';

export default new VueI18n({
  locale,
  messages,
});
