<template>
  <div>
    <ps-accounts class="ms-ps-account-card" :context="contextPsAccounts" />
    <f-button
      variant="primary"
      style="margin-top: 24px"
      :disabled="isPsAccountsOnboarded"
      :loading="loading"
      @click="onContinue"
    >
      {{ $t('general.buttons.continue') }}
    </f-button>
    <f-modal
      :visible="modalVisible"
      :title="$t('installPSAccountModulePage.multiStoreSelection.title')"
      :modal-style="{width: '896px'}"
      :primary-loading="primaryLoading"
      :button-disabled="saveDisable"
      @secondaryAction="onHideModal"
      @primaryAciton="onSave"
      @close="onHideModal"
    >
      <div style="margin-bottom: 32px; margin-left: 8px;">
        {{ $t('installPSAccountModulePage.multiStoreSelection.description') }}
      </div>
      <div style="font-weight: 600; margin-bottom: 16px">
        {{ $t('installPSAccountModulePage.multiStoreSelection.subtitle') }}
      </div>
      <div class="store-options">
        <b-form-radio
          v-for="shop in shops"
          :key="shop.storeName" v-model="selectedUrl"
          :value="shop.url"
          style="margin-bottom: 32px"
          :disabled="shop.disabled"
        >
          {{ shop.storeName }}
        </b-form-radio>
      </div>
    </f-modal>
  </div>
</template>

<script>
import { PsAccounts } from 'prestashop_accounts_vue_components';
import { mapActions, mapState } from 'vuex';

export default {
  components: { PsAccounts },
  data() {
    const user = window.contextPsAccounts?.user;
    const email = user?.email;
    const emailIsValidated = user?.emailIsValidated;
    const isShopContext = window.contextPsAccounts?.isShopContext;
    const shopsInfo = window.contextPsAccounts?.shops;
    const loading = false;
    return {
      user,
      email,
      emailIsValidated,
      isShopContext,
      shopsInfo,
      selectedUrl: null,
      loading,
      primaryLoading: false,
    };
  },
  computed: {
    ...mapState({
      contextPsAccounts: (state) => state.accounts.contextPsAccounts,
      accountStatus: (state) => state.accounts.accountStatus,
    }),
    isPsAccountsOnboarded() {
      return !(this.email !== '' && this.emailIsValidated && this.isShopContext);
    },
    modalVisible() {
      if (this.isShopContext === undefined
      || this.isShopContext === null
      || this.isShopContext === true) {
        return false;
      }
      return true;
    },
    saveDisable() {
      return this.selectedUrl === null;
    },
    shops() {
      const flatternShops = [];
      this.shopsInfo.forEach((group) => {
        const { name, shops } = group;
        shops.forEach((shop) => {
          const storeName = `${name}: ${shop.name}`;
          const { url, domain } = shop;
          const disabled = (domain === null);
          const shopInfo = { storeName, url, disabled };
          flatternShops.push(shopInfo);
        });
      });
      return flatternShops;
    },
  },

  methods: {
    ...mapActions('accounts', ['getAccountStatus']),

    async onContinue() {
      this.loading = true;
      this.$router.push({ name: 'store-requirements' });
    },
    onHideModal() {
      this.modalVisible = false;
      this.$router.push({ name: 'promotion' });
    },
    onSave() {
      this.primaryLoading = true;
      window.location.href = this.selectedUrl;
    },
  },
};
</script>

<style scoped lang="scss">
.store-options {
  overflow-y: auto;
  max-height: 256px;
  width: 40%;
  border: 1px solid #eee;
  padding: 8px;
  border-radius: 4px;
}

</style>
